INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5249545','Зійшла зоря ізвечора','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Українські народні пісні з нотами. Засвічу свічку восковую. - Харків: Фоліо, 2002. - 289 с.',NULL,'Зійшла зоря ізвечора,
Да й стало світать,
Стали воли чумацькії
В степу приставать,
Стали його рідні браття
В степу покидать.

Не кидайте, рідні браття,
Да й на чужині,
Викопайте криниченьку
Да й на камені,
Чи не прийде дівча-рибча
По воду мені.

Прийшла дівча, прийшла рибча,
Стала воду брать,
Ой, взяв чумак за рученьку
Да й став жартувать,
Ой, взяв єї за рученьку
Да й став пригортать.

Прилетіла зозуленька
Да й стала кувать:
Годі, годі, чумаченьку,
З дівчам жартувать,
Ой, час-пора до й озера
Солі набирать.','["pisni.org.ua", "cat:chumacki", "Чумацькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5249545'), datetime('now')),datetime('now'));
