INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_525106','Повитання женців','(А наша їмость не пишна). Українська народна пісня','uk','ukraine_before_1917',NULL,'1913','Колесса Ф. Шкільний співаник. З педагогічної спадщини композитора.- Київ: Музична Україна, 1991.- 224 с.','Першоджерело: Колесса Ф. Обжинки. Етнографічна картина у піснях народних на хор мішаний. Львів, 1913.- с. 24','1. А наша їмость не пишна,
на воротенька вийшла.

2. В ключики подзвонила,
Женчиків погостила.

3. Богу ся помолила,
Що в полю обробила.

4. Ой спи, ґаздине, доволі
Маєш жита в стодолі.    Мелодія для 1 і 2 голосу','["pisni.org.ua", "cat:obzhynkovi", "Обжинкові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_525106'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_525106','Повитання женців','1. А наша їмость не пишна,
на воротенька вийшла.

2. В ключики подзвонила,
Женчиків погостила.

3. Богу ся помолила,
Що в полю обробила.

4. Ой спи, ґаздине, доволі
Маєш жита в стодолі.    Мелодія для 1 і 2 голосу');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5229444','Миколай','Музика: Сергій Петросян Слова: Ірина Доля. Виконує: Віктор Морозов','uk','ukraine_1991',NULL,NULL,'відеозапис',NULL,'Ми від року і до року
Зустрічаємо гостей,
І лише зачуєм кроки,
Вже чекаємо вістей,
Але той, хто прийде нині
Принесе нам чудеса,
І у лісі, і в долині
Миколаєва краса!

Приспів:
Миколаю, не барися,
Не роздумуй, не гадай,
За роботу вже берися,
Подаруночки роздай!

Ми так весело співали,
Дуже чемними були,
А тепер занудьгували,
Як морози загули.
Та летять уже санчата
Через гори і моря,
В небі, хлопчики й дівчата,
Миколаєва зоря!

Приспів.

Ми від року і до року
Зустрічаємо гостей,
І лише зачуєм кроки,
Вже чекаємо вістей.
Але той, хто прийде нині
Принесе нам чудеса,
І у лісі, і в долині
Миколаєва краса!

Приспів. (2)','["pisni.org.ua", "cat:svyatyy-mykolay", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5229444'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5229444','Миколай','Ми від року і до року
