Приспів. (2)');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_5229444_l1','pisniua_5229444','YouTube','https://www.youtube.com/watch?v=ZD0LaU3cdV0','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5250704','Пісенька випускників','Музика: Геннадій Желуденко Слова: Марія Гусєва','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Допоки ще дитинство - наше царство,
Допоки ще живий в нас дух бунтарства,
Допоки ще дружить не розучились,
Допоки зовсім ще не розлучились -
Згадаймо, що у нас лишився рік,
Останній залишився спільний рік,
Останній у житті шкільному рік...

Згадаймо всі його події й дати,
Щоб потім їх по-довше пам''ятати,
І на порозі нашого розпуття
Обітницю дамо їх не забути,
Коли минеться наш останній рік,
Останній наш минеться спільний рік,
Останній у житті шкільному рік...

І у шкільних, останніх вже, сюжетах
Від того серце ще не раз тріпнеться,
Що нашому дзвінкому випускному,
Ще поки безтурботному такому,
Всього лишився лиш останній рік,
Останній залишився спільний рік,
Останній у житті шкільному рік...

Допоки ще дитинство - наше царство,
Допоки ще живий в нас дух бунтарства,
Допоки ще дружить не розучились,
Допоки зовсім ще не розлучились -
Згадаймо, що у нас лишився рік,
Останній залишився спільний рік,
Останній у житті шкільному рік...','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5250704'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5250704','Пісенька випускників','Допоки ще дитинство - наше царство,
Допоки ще живий в нас дух бунтарства,
Допоки ще дружить не розучились,
Допоки зовсім ще не розлучились -
Згадаймо, що у нас лишився рік,
Останній залишився спільний рік,
Останній у житті шкільному рік...

Згадаймо всі його події й дати,
Щоб потім їх по-довше пам''ятати,
І на порозі нашого розпуття
Обітницю дамо їх не забути,
Коли минеться наш останній рік,
Останній наш минеться спільний рік,
Останній у житті шкільному рік...

І у шкільних, останніх вже, сюжетах
Від того серце ще не раз тріпнеться,
Що нашому дзвінкому випускному,
Ще поки безтурботному такому,
Всього лишився лиш останній рік,
Останній залишився спільний рік,
Останній у житті шкільному рік...

Допоки ще дитинство - наше царство,
Допоки ще живий в нас дух бунтарства,
Допоки ще дружить не розучились,
Допоки зовсім ще не розлучились -
Згадаймо, що у нас лишився рік,
Останній залишився спільний рік,
Останній у житті шкільному рік...');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5232747','Гімн Євро-2012','Слова: Микола Джумак','uk','ukraine_1991',NULL,'2012','авторське подання',NULL,'"Ще не вмерла Україна!"
"Іще польска не сгінела!"
Підіймають дві країни
Стяг футболу аж до неба!

Приспів:
Футбол, футбол, футбюол!
Фінал Європи знов
Зібрав на поле всіх,
Хто став сильнішим в грі!
Футбол, футбол, футбол!
Життя твоє - це гол!
Скандує стадіон -
Живе хай чемпіон!

"Ще не вмерла Україна!
"Іще польска не сгінела!"
Два народи всі країни
Зустрічають так у себе!

Приспів.

І квітуча Україна
І вся Польша в цю годину
Слави, честі й перемоги
Всім бажають до знемоги!

Приспів.','["pisni.org.ua", "cat:himny-marshi", "Гимни та марші"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5232747'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5232747','Гімн Євро-2012','"Ще не вмерла Україна!"
"Іще польска не сгінела!"
Підіймають дві країни
Стяг футболу аж до неба!

Приспів:
Футбол, футбол, футбюол!
Фінал Європи знов
Зібрав на поле всіх,
Хто став сильнішим в грі!
Футбол, футбол, футбол!
Життя твоє - це гол!
Скандує стадіон -
Живе хай чемпіон!

"Ще не вмерла Україна!
"Іще польска не сгінела!"
Два народи всі країни
Зустрічають так у себе!

Приспів.

І квітуча Україна
І вся Польша в цю годину
Слави, честі й перемоги
Всім бажають до знемоги!

Приспів.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5252242','Крутянська пісня','Слова: Богдан-Ігор Антонич','uk','ukraine_1991',NULL,'2012','Інформаційний бюлетень ІКААПУ Інформ №28 (218) 2012 рік.',NULL,'Спом''янімо в пісні славу Крутів,
Найсвятіше з наших бойовищ!
Крути! Крути! - смолоскип в майбутнє.

Крути! Крути! Це за Батьківщину
Стати муром, шанцем душ і тіл.
Крути! Крути! Мужньо, воєдино
Прямувати в найсвятішу ціль.

Крути! Крути! Час розплати близько,
Вже червоний ворог кари жде.
Крути! Крути! Вічне бойовисько
За майбутнє, за світліший день.

Крути! Крути! Мужність і посвята,
Вірність, що міцніша понад смерть
Крути! Крути! Горда і завзята
Кличе пісня і веде вперед.','["pisni.org.ua", "cat:istorychni", "Історичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5252242'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5252242','Крутянська пісня','Спом''янімо в пісні славу Крутів,
