INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5252848','Родина','Музика: Микола Янченко Слова: Микола Янченко. Виконує: Ірина Федишин','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ми повертаємось до дому,
Ми повертаємось до дому,
Де нас завжди чекає мама
Кожну мить...
Стара смерека зніме втому, |
Стара смерека зніме втому, |
Що назбиралася за стільки  |
Довгих літ.                | (2)

Приспів:
Давай, родино, нашу пісню заспіваєм,
Її співали і співатимуть завжди!
Нехай летить, нехай вона лунає
Крізь зорепад, крізь дні минулі і роки!

Іде весна, зе нею - літо,
Іде весна, зе нею - літо,
І непомітно пожовтіє перший лист.
Та наш вогонь не загасити, |
Співають з нами наші діти, |
І рідна хата знов радіє,   |
Як колись!                 | (2)

Приспів.

Покличе знову нас дорога,
Покличе знову нас дорога,
Щоб заблудитись в самоті
Тривожних днів.
І кожен день я прошу Бога, |
Щоб темна хмара і тривога  |
Минала всіх нас,           |
Наших дочок і синів.       | (2)

Приспів. (3)','["pisni.org.ua", "cat:pro-batkiv", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5252848'), datetime('now')),datetime('now'));
