INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_525444','Кінець нивонці, кінець','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1980','Пісні з Поділля. - К.: Музична Україна, 1988.','Записана 1980 року в с. Черче Чемеровецького р-ну Хмельниччини від Я.С.Банашко.','Кінець нивонці, кінець.  (2)
