INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5255242','Пісня про маму','Музика: Ірина Батюк Слова: Нестор Мартинець. Виконує: Зоряна Рощук','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Нагадай мені, рідная мамо,
Як в дитинстві колись ти співала,
Біля мене сиділа ночами
І про сон чарівний забувала.
Заспівай мені, рідная мамо,
Про щасливі і радісні дні,
І про те, як у сонячний ранок
Посміхнулась я вперше тобі.

Приспів:
Пролітають роки, мов лелеки,
У незнані ще й досі світи,
Але зіркою в небі далекім
Наді мною світитимеш ти
Оберегом святим у житті!

Розкажи мені, рідная мамо,
Хоч і я в тебе рідна дитина,
Як у Бога щоночі сльозами
Щастя й долі для мене просила.
Заспівай мені, рідная мамо,
І про рідну Вкраїну згадай,
Хоч дороги далекі між нами,
Повертайся до нас в рідний край!

Приспів.','["pisni.org.ua", "cat:pro-batkiv", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5255242'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5255242','Пісня про маму','Нагадай мені, рідная мамо,
