INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5254900','Оберіг','Музика: Михайло Герц Слова: Леся Вознюк','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Вишивала мама синіми ниткам, —
Зацвіли волошки буйно між житами.
Узяла матуся червоненьку нитку, —
Запалали маки у пшениці влітку.

Оберіг-сорочку вишила для сина.
Візерунком стали квіти України:
Маки та волошки, мальви біля хати.
Долю для дитини вишивала мати.

Шила-вишивали хрестики зелені, —
Зашуміло листя на вербі й калині.
Золотилось сонце у розлогій кроні.
Вишивала долю, наче по долоні.

Оберіг-сорочку вишила для сина.
Візерунком стали символи Вкраїни:
І верба, й калина, сонях біля хати.
Щастя для дитини вишивала мати.

Білими по білім вишивала ненька,
До ниток вплітала всю любов серденька.
Дрібно гаптувала росяні мережки,
Щоб не заростали у дитинство стежки.

Оберіг-сорочку вишила для сина.
Візерунком стала рідна Україна.
Мамину турботу збереже сорочка,
Захистять від лиха хрестиків рядочки','["pisni.org.ua", "cat:pro-ditey", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5254900'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5254900','Оберіг','Вишивала мама синіми ниткам, —
