INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_525405','А у лісі ожинки','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1948','Пісні з Львівщини. - К.: Музична Україна, 1988.','*Бербениця - діжечка, бочечка, барилко. Записана 1948 року в с. Крушельниця Сколівського р-ну Львівщини від Б.С.Костіва.','А у лісі ожинки, ожинки, ожинки, ожинки,
