INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_525141','На високій дуже кручі','(Пісня про Шевченка). Музика: Іван Кучеренко-Кучугура Слова: Іван Кучеренко-Кучугура. Виконує: Іван Кучеренко-Кучугура','uk','ukraine_before_1917',NULL,'1874','1. З родини; 2. Українські народні романси. - К.: В-во АН УРСР, 1961. С. 356. 3. Трускавецькі співанки. - К.: Музична Україна, 1989. С. 11.','Аврорство встановив з інтернету: http://ua-reporter.com/text/620/. Там же вказано, що пісню виконує, ансамбль бандуристів Ужгородської дитячої школи мистецтв. Згідно з цим посиланням пісня належить відомому українському кобзарю Іванові Кучугурі-Кучеренку (1874 – 1943). Текст виправлений за джерелом 2. Акорди подані за джерелом 3. У джерелі 3 лише частина поданого тексту з неточностями. У джерелі 2 є посилання на першоджерело: Українські народні пісні, кн. 2. - К.: Мистецтво, 1954. - С. 359.','На високій дуже кручі,
Над самісіньким Дніпром,
Спить Шевченко в домовині  |
Непробудним вічним сном.   |(2)

Любий сину України,
Наш Тарасе дорогий,
Тебе в світі вже немає,    |
А в серцях ти все живий!   |(2)

Твоя кобза ще не вмерла,
На ній струни всі дзвенять,
І про твою вічну славу     |
Всі народи гомонять.       |(2)

Своє слово ми здержали
І зробили, як бажав:
Над Дніпром цим поховали,  |
Щоб ти вічно там лежав.    |(2)

На високій дуже кручі,
Скільки видно над Дніпром,
Спить Шевченко в домовині  |
Непробудним вічним сном.   |(2)
Акорди:
На ви_со____кій ду_же кру__чі,
Над самісіньким Дніпром,
Спить Шевченко в до_мо_ви___ні  |(2)
Непробудним вічним сном.        |','["pisni.org.ua", "cat:dumy", "cat:istorychni", "cat:nostalgia", "cat:patriotic", "Думи", "Історичні пісні", "Пісні з ностальгічними мотивами", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_525141'), datetime('now')),datetime('now'));
