INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5262141','Теща','Українська народна пісня. Виконує: Михайло Березутський','uk','ukraine_before_1917',NULL,NULL,'http://rulyrics.ru/ru/b/berezuts._kij_mihajlo/teshchu_v_choboti.html',NULL,'Узуваю тещу я у чоботи,
Не допущу рідної до роботи.
Буду на руках я її носити,
Цілувати ручку й годити.

Приспів:
Тещу в чоботи узуваю, узуваю,
Тещу мамою називаю, називаю.
В пояс я їй кланяюся низенько,
Буду біля серця їй близенько.
А на тещі чоботи аж риплять,
Вибирав ті чоботи рідний зять.
Щоб вони не муляли і не терли,
Бо рідня тепер ми.

Узуваю в чоботи у новенькі,
Будемо ми з тещею, як рідненькі.
Добровільно піду її в печину,
Бо беру красуню дівчину.

Приспів.

Ой, люблю душею я тещу,
Як вона танцює - я плещу.
А як заспіває - сідаю,
Слухаю й нерепебиваю.

Приспів. (2)','["pisni.org.ua", "cat:vesilni", "Весільні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5262141'), datetime('now')),datetime('now'));
