INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5246508','Козацька доля','Музика: Леонід Попернацький Слова: Володимир Матвієнко. Виконує: Владислав Лєлюшкін','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Сьогодні знов тумани в берегах,
А спогади як вершники в степах.
Душа моя летить до тебе знов,
Окрилення моє - моя любов!

Приспів:
Ой, пісня - доле, моя воленько,
Ласкава будь зі мною, доленько.
Ой, пісня - доле, моя воленько,
Ласкава будь зі мною, доленько!

Козацька пісня славна у віках,
Несу її у серці і в думках.
А ти про мене, люба, не забудь,
Доріженька моя - терниста путь.

Приспів.

Згадаємо, братове, козака,
Весела в нього доля і гірка.
Душа моя летить до нього знов,
Окрилення моє - моя любов.

Приспів','["pisni.org.ua", "cat:kozacki", "cat:poliski", "Козацькі пісні", "Пісні з Полісся"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5246508'), datetime('now')),datetime('now'));
