INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5264807','Соловей, соловейко!','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Соловей, соловейко!
Ой чий же то клин та й не виораний?
Соловей, соловей...

Соловей, соловейко!
Там Микола й орав
Та й плуг поламав.
Соловей, соловей...

