INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_52646','Повіяв вітер степовий','Українська народна пісня. Виконує: Ансамбль Львівського Університету "Черемош", Тріо Мареничів, Буття, Не журись!, Боян','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Повіяв вітер степовий,
C
