INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5264848','О, пані вчителько','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Дитинство золоте - пора прекрасная,
Ох, як ми мріяли йти до зірок.
О, пані вчителько, о, зоре ясная,  |
Згадайте свій перший у школі урок. | (2)

Знаннями чистими, думками світлими
Ви наповняли кожен день, кожен час.
О, пані вчителько, Ви не помітили, |
Як сивина доторкнулася вас...      | (2)

У кожнім учневі частинка власная,
Струмочок серця, любові струна.
О, пані вчителько, о, зоре ясная,  |
Нехай вам доля віддячить сповна!   | (2)','["pisni.org.ua", "cat:devoted", "Пісні присвячені окремим особам"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5264848'), datetime('now')),datetime('now'));
