INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5265747','Тільки друг','Слова: Зоя Солярик','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Хто розрадив тоді,
Як було мені гірко?
Хто всміхнувся мені
Крізь тумани незгод?
Хто зарадив біді,
Як згасаюча зірка
Догоряла в пітьмі
У полоні турбот?

Приспів:
Тільки друг, тільки друг
Не продасть і не зрадить.
Тільки друг, тільки друг
Зрозуміє й простить.
Тільки друг, тільки друг
Скаже гіркую правду.
Тільки друг, тільки друг
Від незгод захистить.

Хто у серці моїм
Тяжкі рани загоїв?
Хто собою мене у бою затуляв?
Хто в години тяжкі
Скаже: "Будьмо з тобою!"
І підставить плече,
Прилетівши здаля?

Приспів.

Що бува, те бува. -
Доля в нас не питає,
Твердо стеле життя,
Часто вітер - в лице.
Хто ж не лиш на словах,
А на ділі подбає
Й не попросить вовік
Нагороди за це?

Приспів.','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5265747'), datetime('now')),datetime('now'));
