тобі - небесний сад.','["pisni.org.ua", "cat:strasni", "Страсні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5271106'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5271106','Хрест Христовий знявся в вись','Хрест Христовий знявся в вись,
