INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5255209','Україно-краю','Музика: О. Матраєв Слова: О. Матраєв. Виконує: Юлія Чорна','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Там, де лине пісня ця,
Верби і тополі,
Заслухавшись солов''я
Сплять річки та гори.

Приспів:
Україно-краю,
Цвіт краси розмаю.
В світі наймиліша
І рідніша ти.

Тут стежки мої, поля,
Сонце променисте,
Друзі милі, вся сім''я -
Чарівне намисто.

Приспів.

Запитати хочу я
У цілого світу:
Де ще є така краса,
Зеленії квіти?..

Приспів.','["pisni.org.ua", "cat:dytyachi", "Дитячі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5255209'), datetime('now')),datetime('now'));
