INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5272900','А ти дівча, як ся маш','Українська народна пісня. Виконує: Мар''яна Садовська','uk','ukraine_before_1917',NULL,NULL,'інтернет',NULL,'А ти дівча, як ся маш,
Що солодку гендзю маш?
Мам солодку, як той мюд,
Як той мюд,
Аж ся за ню хлопці б''ют.

А ти дівча, не мудруй,
Як зачалась, то любуй!
Бо, на моє суміннє,
Бо, на моє суміннє,
Іншу возьму, тебе - нє.

А ти дівча шалене,
Не спозерай на мене,
Лем спозерай на того,
Лем спозерай на того,
Што ти підеш за нього.','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5272900'), datetime('now')),datetime('now'));
