INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5269003','Інтернаціонал','Музика: П''єр Дегейтер Слова: Ежен Потьє','uk','ukraine_1991',NULL,NULL,'Пісні до свят. Муз. Укр. - К., 1975 р.',NULL,'Повстаньте, гнані і голодні,
Робітники усіх країн!
Як у вулкановій безодні,
В серцях у нас клекоче гнів.
Ми всіх катів зітрем на порох,
Повстань же, військо трударів!
Все, що забрав наш лютий ворог,
Щоб повернути, час наспів.

Приспів:
Чуєш? Сурми заграли,    |
Час розплати настав -   |
В Інтернаціоналі        |
Здобудем людських прав! | (2)

Не ждіть рятунку не від кого -
Ні від богів, ні від царів,
Позбудеться ярма тяжкого
Сама сім''я пролетарів.
Пусті слова про право бідних -
Держава дбала не про нас,
Нас мали за рабів негідних...
Доволі кривди і образ!

Приспів.

Лиш ми, робітники, ми - діти
Святої армії труда,
Землею будем володіти,
А паразитів жде біда!..
Тоді ж, як грім під час негоди
Впаде на голови катів,
Нам сонце правди і свободи
Засяє тисяччю вогнів.

Приспів.','["pisni.org.ua", "cat:suspilno-politychni", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5269003'), datetime('now')),datetime('now'));
