INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5275343','Світ наповниться добром','Музика: Патроничі Слова: Патроничі. Виконує: Патроничі','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Знов крутить за вікном,
Й білосніжним сном я лечу,
А, може, сплю...
Ми зачекалися давно
Новорічного кіно,
На душі у нас тепло.

Приспів:
Залишай в старому році
Все, чого не хочеш!
Хай летить собі у даль!
Залунають в кожній хаті
Колядки завзяті -
Світ наповниться добром!
Наповниться...

Сніг прилипа до стріх,
Привітав усіх
З Новим Роком та Різдвом!
Ми зачекалися давно
Новорічного кіно,
На душі у нас тепло.

Приспів.

Хай буде в Новому Році
Все, як ти захочеш,
Мрій і не втрачай надій!
Залунають в кожній хаті
Колядки завзяті -
Світ наповниться добром!
Наповниться добром','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5275343'), datetime('now')),datetime('now'));
