INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_526949','Люди, як кораблі','Музика: Андрій Кузьменко Слова: Андрій Кузьменко. Виконує: Скрябін','uk','ukraine_1991',NULL,NULL,'1. http://skryabin.ru/lyrics/ljudy_jak_korabli.shtml; 2. Аудіо-CD "Скрябін. "Танґо" (2005)','Текст взято з офіційного інтернет-джерела [1]. Акорди підібрано на слух, спрощено, в ориганільні тональності. Для спрощення акорд F6* можна не грати. В тональності "Em" акорди такі: - Вступ (і програші): Em Am D D7 D6* - Куплет: | Em Am D | D7 D6* Em | Am D | D7 D6* Em | - Куплет перед приспівом: | Em Am D | D7 D6* Em | Am D | D7 D6* Hm | - Приспів: | Hm Em Am | D Hm | Em Am | D Em | Деякі використані акорди: F6* [x 3 x 2 3 1] D6* [x x 0 2 0 2] Підбір акордів: bohdanko (www.pisni.org.ua)','Вступ: Gm Cm F F7 F6*
Я не твій брат - ти не сестра моя
F7         F6*     Gm
Ніколи не розказуй мені -
хто і в чому є винний на нашій землі -
F7      F6*        Gm
Люди,   як кораблі
Кожен пливе поки хвиля несе
F7      F6*    Gm
і поки глибока вода
Глибока і темна до самого дна
F7     F6*     Gm
До самого-самого дна
Програш: Gm Cm F F7 F6* (x2)
На глибині зустрічаються всі
F7          F6*     Gm
Так ніби в морі місця нема
І труться бортами, аж стогне земля
F7       F6*         Gm
від зависті, підлості й зла
Хтось не доплив Бо йому помогли
F7         F6*     Gm
набрати повні трюми води
Бо стати героями тої війни
F7     F6*    Dm
дуже хотіли вони
Приспів:
А до берега тихо хвилі несуть
Поранені душі живих кораблів
А від берега знову в море ідуть
Ті хто вірив і правду знати хотів
Програш:  Gm Cm F F7 F6*
Наш Океан знає більше ніж ми
F7       F6*         Gm
Секрети всі у нього на дні
А ми ходим зверху, великі й малі
F7      F6*        Gm
Люди як кораблі
Гордо пливем - і не вірить ніхто
F7      F6*       Gm
Шо ним зацікавилось зло
І серед вітрів ми не чуєм щурів,
F7       F6*        Gm
які прогризають нам дно
Приспів.
* F6[x3x231]
Простіші акорди, з капо на 3 ладі
або без капо для нижчого голосу:
Вступ: Em Am D D7 D6*
Я не твій брат - ти не сестра моя
D7         D6*     Em
Ніколи не розказуй мені -
хто і в чому є винний на нашій землі -
D7    D6*     Em
Люди, як кораблі
Кожен пливе поки хвиля несе
D7      D6*    Em
і поки глибока вода
Глибока і темна до самого дна
D7     D6*     Em
До самого-самого дна
Програш: Em Am D D7 D6* (x2)
На глибині зустрічаються всі
D7          D6*     Em
Так ніби в морі місця нема
І труться бортами, аж стогне земля
D7       D6*         Em
від зависті, підлості й зла
Хтось не доплив Бо йому помогли
D7          D6*    Em
набрати повні трюми води
Бо стати героями тої війни
D7     D6*    Bm
дуже хотіли вони
Приспів:
А до берега тихо хвилі несуть
Поранені душі живих кораблів
А від берега знову в море ідуть
Ті хто вірив і правду знати хотів
Програш:  Em Am D D7 D6*
Наш Океан знає більше ніж ми
D7       D6*         Em
Секрети всі у нього на дні
А ми ходим зверху, великі й малі
D7   D6*     Em
Люди як кораблі
Гордо пливем - і не вірить ніхто
D7      D6*       Em
Шо ним зацікавилось зло
І серед вітрів ми не чуєм щурів,
D7       D6*        Em
які прогризають нам дно
Приспів.
* D6[xx0202]','["pisni.org.ua", "cat:philosophic", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_526949'), datetime('now')),datetime('now'));
