INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5276848','Запах квітів','Музика: Ілля Найда Слова: Ілля Найда. Виконує: Ілля Найда','uk','ukraine_1991',NULL,NULL,'Завантажити можна тут: http://wxu.su/music_poisk/song/50185/826941/?page=1',NULL,'Не одна вже минула зима та сніг мете,
Не одна щебетала весна та дощ паде,
Я на гору високу піду, знайду тебе,
Бо кохання у серці моїм не пройде,
Не пройде...

Приспів:
Запах квітів            |
Нам приносить кохання,  |
А кохання нам приносить |
Страждання.             |
Ти для мене             |
В цьому світі остання,  |
Ти остання...           | (2)

Хоч роки, як вода, пропливуть і дощ пройде,
Хоч багато в житті я зроблю - та все мине,
Тільки ти не забудь, як люблю одну тебе,
І кохання у серці моїм не пройде, не пройде...

Приспів. (2)','["pisni.org.ua", "cat:nostalgia", "Пісні з ностальгічними мотивами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5276848'), datetime('now')),datetime('now'));
