INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_5270209_l1','pisniua_5270209','YouTube','https://www.youtube.com/watch?v=xjECz0VSMRo','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5280141','Троянди для вчительки','Музика: І. Тарнавська Слова: Т. Загоруй','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Це для вчительки троянда,
Не звичайна, дуже дивна,
Я її поцілував,
Я їй пісню проспівав -
І тепер вона чарівна.
Не сполохані ще звуки
І дрімає ще рояль,
Я зайду тихенько в клас:
Ось троянда — це для вас,
Люба вчителька моя!

Приспів:
Доторкнуся до руки,
Цілую пальчики.
Мріють сонні клавіші
Про теплий дощик.
Доторкнуся до руки,
Грайте, пальчики.
Допоки музика в душі,
Аж доти.

І мені скоряться ноти,
Як незвідані світи.
І трояндам, і зіркам,
І замріяним струмкам
Я співатиму завжди.

Приспів.','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5280141'), datetime('now')),datetime('now'));
