INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5282848','Весна над Україною...','Українська народна пісня','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пам''яті всіх замордованих катами свого народу, відомих і безіменних, тих, чия доля так і залишиться невідомою, а їх багато...','Весна над Україною... Весна...
Вертають птахи із країв далеких,
А я до дому вже не повернусь,
Чомусь, у це повірити нелегко...

Я знаю, ти молилась день і ніч,
Матусю рідна, за свого синочка
І до грудей, мов найціннішу річ,
Тулила мою вишиту сорочку...

Моя рідненька, не чекай мене,
У тишу ночі не вслухайсь тривожно,
Синочок твій ніколи не прийде,
Бо звідти повернутись вже не можна...

Як добре, мамо, що не знаєш ти,
Які синок терпів страшенні муки,
Але мені ніщо вже не болить,
У Ангелів такі ласкаві руки...

А ти чекаєш... Тільки не вернусь
До тебе, рідна, навіть в домовині.
Та не пропав я... Я віддав життя
Своє, матусю, неньці Україні!..','["pisni.org.ua", "cat:euromaydan", "Пісні Євромайдану"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5282848'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5282848','Весна над Україною...','Весна над Україною... Весна...
Вертають птахи із країв далеких,
