INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5282807','Не питай мене, мамо...','Українська народна пісня','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Не питай мене мамо,
Чом не сплю я і плачу вночі.
Йду туди, де стріляли,
Дві червоні гвоздики несу у руці...

Запалю я вогонь, постою тут хвилину,
Страшний біль не мина...
Наш герой залишив сироту Україну -
Найболючішу втрату відчула вона...

Я впаду на коліна,
Бо не сила стояти на рівних ногах...
Поруч мати за сина
Біль стискає в скорботних сльозах...

Покладу тії квіти
Найсильнішої сотні до ніг.
Прости, славний син України,
Твій народ, що тебе не вберіг...

Кат не буде на волі
І йому вже нема каяття!
Знайте, хлопці, не дарма віддали
За майбутнє своє найцінніше - життя!..

Розквітає у серці героя цвіт вишні,
Так приходить весна,
І Небесної сотні усмішки дарує Всевишній,
Україна у нього одна!..','["pisni.org.ua", "cat:euromaydan", "Пісні Євромайдану"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5282807'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5282807','Не питай мене, мамо...','Не питай мене мамо,
Чом не сплю я і плачу вночі.
Йду туди, де стріляли,
