INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5287040','Гав-гу, вовки!','Музика: сктм. о. Б.Ганушевський Слова: Олександр Тисовський. Виконує: Оксана Муха','uk','ukr_ssr_1919_1991',NULL,'1947','Пластовий співаник "В дорогу", 1947 р.','Пластова пісня, зложена для 2. Гуртка 5. Куреня УПЮ ім. Хв. Черника в Міттенвальді 1947 р. Музика: сктм. о. Б.Ганушевський','Гав-гу! Вовки, вже ліс шумить,
Крізь гілля розсвіт загляда...
З''яснів обрій, роса тремтить,
Вітрець вже мряки розганя!
Гав-гу! Гав-гу!
Позір, Вовки! Журчить ручай,
З просоння очі сполочіть,
Зберім що ваше, в ряд ставай!
Тихцем, бо ворог нас слідить!
Гав-гу! Гав-гу!
Ходом, Вовки! В цей чорний бір
Ваш крок сміливо хай ступа,
Завзяттям хай палає зір,
Бо рідна нам оця земля!
Гав-гу! Гав-гу!
Вперед, Вовки! Хоч жде нас труд,
Бо з пітьмою нелегкий бій...
Ми вирвемось з ворожих пут,
На вольний вийдемо обрій!
Гав-гу! Гав-гу!','["pisni.org.ua", "cat:plastovi", "Пластові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5287040'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5287040','Гав-гу, вовки!','Гав-гу! Вовки, вже ліс шумить,
Крізь гілля розсвіт загляда...
З''яснів обрій, роса тремтить,
