Гав-гу! Гав-гу!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5286747','Коломийки','Українська народна пісня. Виконує: ВІА Світязь','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'У неділю на подвір''ї
Музики заграли,
У неділю на подвір''ї
Усі танцювали.

Так заграйте, музиченьки,
У струну тоненьку,
Та беру я танцювати
Дівку молоденьку.

Ходи, дівко, танцювати,
Ходи, дівко, в танець,
Не була-сь би така файна,
Якби не рум''янець.

Ой, до танцю, легіники,
До танцю, до танцю,
Беріть собі по дівчині,
Мені лишіть п''янцю.

Як не любиш білявого,
Люби мя самого,
Не позирай через плече
На цимбору мого.

У неділю на подвір''ї
Музики заграли,
У неділю на подвір''ї
Усі танцювали','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5286747'), datetime('now')),datetime('now'));
