INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5289141','Разом і до кінця!','Музика: Олександр Ступак Слова: Юрій Михалечко. Виконує: Вітер Знає','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Київ, Львів, Херсон, Полтава
Поруч на майдані стали,
Б''ються, як одне, серця.

Приспів:
Разом і до кінця!
Разом і до кінця!
Разом! І до кінця!
Зможемо я і ти   |
Разом перемогти! | (2)

Проти зради, проти крові
Ми боротися готові
До останнього бійця!

