INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_5272343_l1','pisniua_5272343','YouTube','https://www.youtube.com/watch?v=blTY_K0a0CU','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5296646','До нашого храму','Українська народна пісня','uk','ukraine_1991',NULL,'2012','Співаник на прощу. Вигода. Стрий-Зарваниця, 2012 рік.',NULL,'До нашого храму ведуть всі дороги,
Там Божії дзвони гудуть.
До нашого храму, до нашого храму
Народи, як води, пливуть.

О, Матінко, зоре, до Тебе прийшли ми
Живої напитись води.
Ми просимо Бога, ми молимо Бога
Веди нас до Нього, веди!

З гаїв солов''їних Тобі принесли ми
Букети живих квіточок.
Ми просимо Бога, ми просимо Бога
За наших малих діточок.

Матінко миру, прийми любов щиру,
Прийми наші мольби і спів.
Ми просимо Бога, ми просимо Бога
За наших дочок і синів.

Ми хочем, щоб діти навчились молитви,
Щоб чули вони Божий дзвін.
Ми просимо Бога, ми просимо Бога,
Бо сонце любови - це Він.

Благаєм за поле, благаєм за море,
Благаєм за села й міста.
Ми просимо Бога, ми просимо Бога,
Без Нього нема нам життя.

Без нашого Бога земля догоряє
У полум''ї лютих незгод.
Ми просимо Бога, ми просимо Бога,
Лиш Він захистить наш народ.

О, Матінко зоре, втопи наше горе
У ріках живої води.
Ми просимо Бога, ми просимо Бога,
Веди нас до Нього, веди!','["pisni.org.ua", "cat:christian", "Пісні на християнську тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5296646'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5296646','До нашого храму','До нашого храму ведуть всі дороги,
Там Божії дзвони гудуть.
