INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_529040','Ой на Горі тай Женці жнуть','Українська народна пісня. Виконує: Журборіз','uk','ukraine_before_1917',NULL,NULL,'1. Червоная калинонька. - К.: Музична Україна, 1988','Це відміна з додатковою в''язкою про пана хорунжого, яка присутня вже у збірнику Максимовича 1827р.: Українські пісні, видані М. Максимовичем. Фотокопія видання 1827р. (Малороссійскія пЂсни, изданныя М. Максимовичемъ. Москва, Въ Типографии Августа Семена 1827) Підготовка видання і розвідка П.М. Попова. Київ, АН УРСР 1962. 342с. Інші відміни цієї пісні: Гей на горі, там женці жнуть*; Гей на горі, там женці жнуть Сагайдачний, Петро Конашевич. Пара-Непара. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Нема в світі Правди не зіскати. Чого Старий не женишся. Козак старий все в поxодаx. Іще живі та здорові Всі Родичі Гарбузові. Листки з приводу цієї Пісні: Українські реліґійні роздуми про Неволю та Спасіння Традиції самогуртування: Cвятий Збір. Вістуни великого Свята, аскети, люди ідеї. Стежки до листків про Українські традиції.','Ой на Горі тай Женці жнуть       | (2)
А попід Горою яром-долиною Козаки йдуть
Гей долиною гей широкою Козаки йдуть!

Попереду Дорошенко               | (2)
Веде своє військо військо запорізьке хорошенько
Гей долиною гей широкою хорошенько!

Посеpедині/посереду пан хоpунжий | (2)
Під ним кониченько,
під ним воpоненький сильно дужий
Гей долиною гей широкою сильно дужий!

А позаду Сагайдачний             | (2)
Що проміняв жінку на тютюн та люльку необачний
Гей долиною гей широкою необачний!

Гей вернися Сагайдачний          | (2)
Візьми свою жінку віддай тютюн-люльку необачний
Гей долиною гей широкою необачний!

З жінкою в поході не возиться    | (2)
А тютюн та люлька Козаку в дорозі знадобиться!
Гей долиною гей широкою знадобиться!

Гей хто в лісі озовися           | (2)
Та викришем вогню та затягнем люльку не журися!
Гей долиною гей широкою не журися!','["pisni.org.ua", "cat:himny-marshi", "cat:istorychni", "cat:kozacki", "cat:narodni", "cat:patriotic", "cat:philosophic", "cat:suspilno-politychni", "Гимни та марші", "Історичні пісні", "Козацькі пісні", "Народні пісні", "Патріотичні пісні", "Філософські пісні", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_529040'), datetime('now')),datetime('now'));
