INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5289405','Святкова','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Гей, давайте з усіма
Будемо співати!
Свята кращого нема,
Як сьогодні свято.

Приспів:
Новий рік! Новий рік!
Пісенька лунає.
За віконцем на поріг
Сніг-сніжок лягає.
Вся ялинка в іграшках -
Кульки, намистинки...
Он бурульки на гілках,
Зірочки, сніжинки.

Приспів.

В хоровод веселий свій
Стали всі хлоп''ята,
І стрічають рік Новий
Білки, зайченята.

Приспів. (2)','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5289405'), datetime('now')),datetime('now'));
