INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5301747','Дорослий син',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Дорослий син і можна порадіти
Та мимоволі смуток огорта.
Чому так швидко виростають діти?
А в матерів ніхто і не пита...
І ось вже час віщує нам розлуку,
І мій синок від долі не втече,
Зато вже можу не тримать за руку
І, навіть, спертись на його плече.

Приспів:
Дорослий син - бентежне відчуття,
Для мене він - завжди мале дитя,
Це завдяки йому я зрозуміла,
Я зрозуміла в чому сенс життя!..

Можливо, я і не найкраща мати,
Холодним вітром сумнів студить кров,
Та що я можу своєму сину дати -
Лише любов, лише свою любов...
А скарб найбільший, знаєш, мій синочку,
Всі ці роки я в шафі берегла,
Цю крихітну батистову сорочку,
В якій тебе додому принесла.

Приспів.

Спокуси, перешкоди, пересуди
Але одне з тобою знаєм ми,
Мені ніколи соромно не буде
За тебе, сину мій, перед людьми.
Майне у небо зграя журавлина,
Сльоза важка на віях забринить,
Я в світ широкий відпускаю сина -
Лети, мій хлопчик, хай тобі щастить!

Приспів.','["pisni.org.ua", "cat:pro-ditey", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5301747'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5301747','Дорослий син','Дорослий син і можна порадіти
