INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_529949','Ликуючи, возіграймо!','Українська народна пісня. Виконує: Ансамбль Львівського Університету "Черемош"','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'На радощах заспіваймо днесь!
Явилась нам благодать з небес:
Бог нам народився з Марії,
Непорочної Лелії,
У мирі для нас,
У мирі для нас.

Ти, Йосифе, з нами торжествуй!
Ти, Давиде, разом празникуй.
Це для нас всіх Гість пожаданий,
Емануіл, з неба зісланний,
Так сказав пророк.      | (2)

Царі зі сходу поспішають
До Вифлеєму прибувають
Золото, ладан і смирну в дарі
Небесному несуть царю
І кладуть до ніг.       |(2)

І ми Богу хвалу віддаймо,
Родженому піснь заспіваймо,
Щоб дозволив нам раювати,
З Ангелами враз прославляти
Нам Його повік.         | (2)','["pisni.org.ua", "cat:cerkovni", "Церковні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_529949'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_529949','Ликуючи, возіграймо!','На радощах заспіваймо днесь!
Явилась нам благодать з небес:
Бог нам народився з Марії,
