INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_529900','А ми просо сiяли','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'http://www.artdevice.dp.ua/work/dyk/song/song1.html','Веснянка-гра: два гурти стають один проти одного, співають почережно й імітують все те, про що співають. Інші варіанти цієї пісні: Ой посієм овес; Ой ми нивку горемо, горемо','1-й гурт: — А ми просо сіяли, сіяли,
