INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5308003','Чом ти, місяцю, не сяєш','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Ігри та пісні. Весняно-літня поезія трудового року. - Київ: Вид. АН УРСР, 1963.',NULL,'Чом ти, місяцю, не сяєш?
Чом ти, Миколо, не сядеш?

Десь ти Ганусі не любиш,
Що ти їй віночка не купиш.

Якби я її не любив,
То я б до неї не ходив.

То я б до неї не ходив,
В руках шапочки не носив.

В руках шапочки не носив,
Її батенька не просив.

Чорная шапочка на кілку,
Ти ж, моя Ганусю, у вінку.','["pisni.org.ua", "cat:kupalski", "Купальські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5308003'), datetime('now')),datetime('now'));
