INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5301704','Матінка моя','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Чи хмарина в небі хмуриться,
Чи сніжок летить в саду,
Я в вікно дивлюсь на вулицю
І з роботи маму жду!

Приспів:
Нехай же знає вітер,   |
І зорі, і моря,        |
Найкраща в цілім світі |
Матінка моя!           | (2)

Не біда, як грім гулятиме,
Дощик сіє - ну й дарма?,
Лиш згадаю усміх матері -
Й краплі страху вже нема!

Приспів.

Обніму я щиро навесні
Рідну матінку свою,
Дам дарунок їй, збентеженій,
В пісні радість переллю!

Приспів.','["pisni.org.ua", "cat:pro-batkiv", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5301704'), datetime('now')),datetime('now'));
