INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_531747','Ой чиї то Воли по Горі ходили','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Ой чиї то Воли по Горі ходили — Еротика: Катерини – Калета – Андрія... Зелені Свята... Гаївки-Великдень... Весілля... Прийди-прийди Серденя на Пухові Подушки. Читати листки, де є згадка з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Стежки до інших листків про Українські пісні. Ой чиї то Воли по Горі ходили','Ой чиї то Воли по Горі ходили
Ой то того Козаченька що ми втрьох любили  -2

Первая любила правду говорила
А Другая полюбила только подарила -2

Третяя любила Білу Постіль слала
Вона слала вистилала ще й причарувала -2

Чаруй Дівко чаруй поки й чаруєцця
Бо вже ж твоє біле личко з моїм спознаєцця -2

Забряжчали ключі з Комори ідучи
Заплакав же Козаченько од Дивчини йдучи -2

Як почула Мати ще й загомоніла
Коб я знала мій Синочку сім літ оженила -2','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_531747'), datetime('now')),datetime('now'));
