INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_5313405_l1','pisniua_5313405','YouTube','https://www.youtube.com/watch?v=AoYQaZaA10s','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5317003','Ви в дні весняні положили життя','(Жалібний марш). Українська народна пісня. Виконує: Тарас Компаніченко','uk','ukraine_1991',NULL,'2014','Варіант слів додав GoblinShepherd','Цю пісню виконував на кобзі Тарас Компаніченко, коли гинули герої на Майдані. Вперше жалібний марш Тарас Компаніченко виконав 22 лютого 2014 р. Варіант слів додав GoblinShepherd','Ви в дні весняні положили життя
На вівтар святий України.
Вам руки дівочі не клали квіття,
Не несли брати домовини.

Останній цілунок на Вашім чолі
Не склали матуся ні тато.
Ніхто не світив Вам свічок в головах,
Брати не прийшли поховати.

Тортури і смерть не змогли Вас зломить.
Ви тайну забрали в могилу.
По бурнім житті Ви пішли спочивать
За чесне, священнеє діло.

Ви жертвами в бою нерівнім лягли
З любові до свого народу.
Ви все віддали за його, що змогли:
І щастя, і честь, і свободу.

За Вами борців уже тисяча йде
Не смерть і на жертву готові.
Прощайте ж Ви браття, Ви чесно пройшли
Велику дорогу любові.

Не сурмили сурми Вам марш жалібний.
Не справила тризну родина.
Сповнили Ви народу приказ святий
Вам вдячна за це Україна!

Відміна слів:
Ви в дні весняні положили життя
На вівтар святий України.
Вам руки дівочі поклали квіття
І несли брати домовини.

Останній цілунок на вашім чолі          |
Поклали матуся і тато.                  |
Майдан засвітив вам свічок в голові,    |
Брати вас прийшли поховати.             | (2)

Тортури і смерть не змогли вас зломить,
Ви тайну забрали в могилу.
По бурнім життю ви пішли спочивать
За чесне, священнеє діло.

Засурмили сурми вам марш жалібний       |
І справила тризну родина.               |
Сповнили ви народу приказ святий,       |
Вам вдячна за це Україна.               | (2)

Ви жертвою в бою нерівнім лягли
З любови до свого народу.
Ви все віддали за його, що могли:
І щастя, і честь, і свободу.

За вами борців уже тисяча йде:          |
На смерть і на жертву готова.           |
Прощайте ж, ви браття, ви чесно пройшли |
Велику дорогу любови.                   | (2)','["pisni.org.ua", "cat:euromaydan", "Пісні Євромайдану"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5317003'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5317003','Ви в дні весняні положили життя','Ви в дні весняні положили життя
