Приспів.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_53209','Гей, наливайте повнії чари','(Гей нумо Хлопці Славні Молодці). Українська народна пісня. Виконує: Дударик, Микола Шопша','uk','ukraine_before_1917',NULL,NULL,'1. Туристський пісенник "Де гори Карпати де Писаний Камінь". - Літо, 1982.','*Відміна тексту, акорди акомпанементу подані за джерелом 1.','Гей, наливайте повнії чари,
Щоб через вінця лилося.
Щоб наша доля нас не цуралась,   |
Щоб краще в світі жилося.        | (2)

Вдармо об землю лихом-журбою
Щоб стало всім веселіше!
Вип''єм за щастя, вип''єм за долю, |
Вип''єм за все що миліше.         | (2)

Гей нумо, хлопці, славні молодці,
Чом ви сумні, невеселі?
Чи у шинкарки мало горілки,      |
Пива чи меду не стало?           | (2)

Пиймо, панове, пиймо, братове,
Пиймо, поки іще п''ється!
Поки недоля нас не спіткала,     |
Поки ще лихо сміється.           | (2)

Гей, наливайте повнії чари,
Щоб через вінця лилося.
Щоб наша доля нас не цуралась,   |
Щоб краще в святі жилося.        | (2)
Відміна:*
Гей нуте хлопці славні молодці
Чом ви смутні невеселі
Хіба в шинкарки мало горілки     |(2)
Пива і меду не ста___ло ?        |

Гей наливайте повнії чари
Щоб через вінця лилося
Щоб наша доля нас не цуралась    |
Щоб краще в світі жилося !       | (2)

Вдармо ж об землю лихом-журбою
Щоб стало всім веселіше
Вип''єм за щастя вип''єм за долю   |
Вип''єм за все що рідніше !       | (2)

Щоб наша доля нам засіяла
Мов тая зіронька з неба
Доленька тая — воля святая       |
Більшого щастя не треба !        | (2)

Пиймо ж панове пиймо братове
Пиймо покіль іще п''ється
Поки недоля нас не спіткала      |
Поки ще лихо сміється !          | (2)','["pisni.org.ua", "cat:himny-marshi", "cat:narodni", "cat:patriotic", "Гимни та марші", "Народні пісні", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_53209'), datetime('now')),datetime('now'));
