INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_530545','Рано раненько','Українська народна пісня. Виконує: Софія Федина','uk','ukraine_1991',NULL,'2005',NULL,'Пісня включена в Альбом колядок Софії Федини "Новая Зоря"(2005)','Ми з колядою під ваші стріхи
