INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5333508','Марш ВМС України','Музика: Валерій Громцев Слова: Леонід Курявенко. Виконує: Олександр Іванов','uk','ukraine_1991',NULL,NULL,'власна аудіокасета, Вікіпедія','Виконує: Олександр Іванов {3926} Альбом: Море об''єднало нас','Нашої державності оплот,
Кримського південного кордону —
Український Чорноморський флот
Забезпечить міцну оборону.
Синьо-жовтий прапор майорить,
Прийнята присяга Україні,
Будуть вірно моряки служить
Незалежній молодій країні.

Приспів:
Браття! Послужим Україні ми!       |
За Чорне море станемо грудьми!     |
За наш чудовий і чарівний Крим!    |
За Український прапор, що над ним! | (2)

Хай завжди на морі буде штиль.
А коли проб''є сигнал тривоги —
Моряки підуть напроти хвиль
І піднімуть прапор Перемоги.
Бачить Бог, державності оплот,
Кримського південного кордону —
Український Чорноморський флот
Забезпечить міцну оборону.

Приспів. (2)','["pisni.org.ua", "cat:himny-marshi", "Гимни та марші"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5333508'), datetime('now')),datetime('now'));
