INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_533508','Ой ходили та блудили Три Коляднички','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядка стародавня: Українське Різдво Світа. Буде в Тебе Господь на Вечері. Ой там виxодило та Три Товариші. Листки з приводу цієї Пісні: Ідея Бога на Свят-Вечер. День реліґійно-філософських роздумів на Астральні теми, Варвари 17.12. Українські релігійні роздуми про Бога: Яблучко. Стежки до листків про Українські традиції.','Ой ходили та блудили Три Коляднички

Приспів:
Виноград Ой Красне Зельоне Вино !

Тай шукали тай питали Цього Пана Двора
Ой це Того Пана Двір що Високий Частокіл

Що Миколка на Конику величається
Ой його Отець-та-Матуся утішаються
Ой ти Синку ти Миколко ой ти Чадо Моє
Не служи ти королю служи Богу-царю
Кришталеві Ворітця й одчиняються','["pisni.org.ua", "cat:shchedrivky", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_533508'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_533508','Ой ходили та блудили Три Коляднички','Ой ходили та блудили Три Коляднички

