INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_532601','Ой на Йвана Зілля рвала в Городі садила','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пара - любощі: Город-Зілля. Оріхи - Повна Опівочка. Вибір Пари. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. Межи всіми Парубками Йвана полюбила. Миленькому на Колядку а й на Щедрівочку. Були Світилки Яснії Зірки. Лишилася по й Івану Гарна Співаночка. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','Ой на Йвана Зілля рвала в Городі садила
Межи всіми Парубками Йвана полюбила     |(2)

Нема Йвана нема Йвана нема й Іваночка
Лишилася по й Івану Гарна Співаночка    |(2)

Ой кобуло ни гриміло на самого Йвана
Я би свому Миленькому Оріхів нарвала    |(2)

Ой нарвала тай сховала Повну Опівочку
