INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5336545','Намалюю я','Слова: Галина Британ','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує Поліна Бойцова (вокальна студія "Фора", м. Львів, керівник - Заслужений артист України Володимир Кудовба).','Фарби дасть мені матуся,
Пензля я візьму,
Намалюю я квітучу
Сонячну весну.

Приспів:
Сонечко світить,
Хмаронька пливе,
На моїм малюнку
Природа оживе!

Квіточку яскраву
Намалюю я і струмок,
І біля нього -
Миле кошеня.

Приспів.

Деревце красиве
Намалюю я,
На зеленій гілочці -
Пташку солов''я.

Приспів.

Півня голосистого
Намалюю я -
Ось яка чудова вийшла
Сонячна весна!

Приспів.','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5336545'), datetime('now')),datetime('now'));
