INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5334141','З Новим Роком, Україно!','Музика: Євген Дашин Слова: Ірина Федишин, Євген Дашин. Виконує: Ірина Федишин','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Місяць уночі гуляє,
В небі зорі розкидає,
Світлом вся земля палає,
В кожну хату свято йде!
Білим снігом по коліна
Вкрило нашу Україну,
Заморозило хатину,
Новий Рік літає вже!
З Новим Роком!

Приспів:
З Новим Роком, Україно!
Наша пісня гарна лине,
Заливає хуртовина,
Снігом вкрилася земля!
Всі скоріш виходьте з хати,
Будем разом святкувати,
З Новим Роком всіх вітати,
Веселись, сім''я моя!

Ходять люди в кожну хату
Україну привітати:
Щастя й радості бажати,
Сіяти зерно своє!
Хай Господь та, добрі люди,
В серці з вами завжди буде,
Допоможе й не забуде
Там, де любов живе!
З Новим Роком!

Приспів. (2)

З Новим Роком!
З новим щастям!','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5334141'), datetime('now')),datetime('now'));
