INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5338040','На вушко','Виконує: Дует Анна-Марія','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Засипає білим снігом зима
І чекає кожен диво,
І бажає всім...
Ти зігрієш моє серце,
А я зігріваю твої руки
Подихом своїм...
В небі тисячі вогнів,
Знаєш, це для нас двоїх,
Кращі друзі навкруги,
Ми попросим.

Приспів:
Разом з нами всім співати
І вітати з Новим роком!
Білим снігом засипати
І вітати з Новим роком!

Поцілунки і обійми лови,
І сніжинку ти на щастя
Собі залиши.
Новий рік дарує радість
І ти подаруєш мені щастя,
Ну а я тобі
В небі тисячі вогнів!
Знаєш, це для нас двоїх,
Кращі друзі навкруги,
Ми попросим.

Приспів.

Подарунки загортати
І вітати з Новим роком,
Щось на вушко прошептати
І вітати з Новим роком,
З Новим роком!
На Новий рік подарунки
Мені подаруєш,
Під ялинку підкладеш
І гарно запакуєш.
О 12-тій годині
Поцілуй і обніми,
Та найкращий подарунок
Для мене то є ти!
Буде весело сьогодні у нас, у вас,
У них, у тих і взагалі у всіх!
На Ямайці, в Гондурасі,
У Канаді, у Канзасі -
Та на нашій Україні краще за усіх!

Приспів.

Щось на вушко прошептати
І вітати з Новим роком,
З Новим роком!','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5338040'), datetime('now')),datetime('now'));
