INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_53242','Лелека','Музика: Ігор Особік Слова: Ігор Особік. Виконує: Андрій Хавунка','uk','ukraine_1991',NULL,NULL,'Збірник пісень Студентського братства Львівської політехніки.- Львів, 2000.',NULL,'Лелека полетів по небу в далечінь,
І жалібний крик прощання до весни.

Приспів:
Ой не плачте ви, сивії верби,
Ваш лелека ще ся поверне.
Поверне, як не згине в далекому краю,
То з весною він ся повертає.

Вже повно в ставках ваших сліз,
Чому ж ви ще плачете верби?
По нашій ненашій землі,
І по тих, кого не повернеш.

Приспів.

Ну що ж ви сестри мої всі навзрид,
Вже гіркая вода в ставочку,
Бо цурається батька син
І плюндрує землю і мову.

Приспів.

Лелека полетів по небу в далечінь...','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_53242'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_53242','Лелека','Лелека полетів по небу в далечінь,
