INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_534704','Заповіт юних стрільців, що впали в бою під Крутами','Українська народна пісня','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'Записав у 1980-х у Москві від побратима по навчанню','Присвячено Подвигу Героїв Крут: "Вони - студенти, курсанти, школярі... без вагань віддали молоде життя в ім''я волі свого народу... Це - символ нескореного духу нашої нації. Це - пересторога тим, хто і нині сподівається поставити націю на коліна..." Детальніше >>','Під Крутами там молоде юнацтво
На прю криваву з ворогами стало
За Україну, славу, честь й багатство
Життя юнацьке своє там віддало.

Клянемось вам, ровесники-герої,
На вашу кров, на славно вічні Крути
Нам чину вашого і жертви пресвятої
Нігде, ніколи не забути!

Клянемось вам для оборони чести
Ваш заповіт аж до кінця сповнити,
Підняти прапор, вгору ген піднести
До ясних зір у сонячні блакити.

За наш народ, за край веселий гожий
Клянемось дружно у потребі стати,
Здобути правду поможи нам, Боже,
І нас благослови, Пречиста Мати.','["pisni.org.ua", "cat:himny-marshi", "cat:kruty", "cat:strilecki", "Гимни та марші", "Пісні пам''яті Героїв бою під Крутами", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_534704'), datetime('now')),datetime('now'));
