INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5350900','Там у лісі дві підводи','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,NULL,'Фольклорний колектив смт. Печеніжин.','Пісня з циклу УПА.','Там у лісі дві підводи,
На підводі чорний хрест,
А з підводи чути голос,     |
Що мені уже конец.          | (2)

На підводі санітарка,
Її серцю жаль було,
Її мужа розстріляли -       |
Серце кров''ю залилось.      | (2)

Вона пише, він диктує:
Як ся маєш дорога?
Я на фронті легко ранений,  |
Скоро дома буду я.          | (2)

Одна рана не велика,
По коліна без ноги,
Друга рана чуть замітна,    |
По плече нема руки.         | (2)

Як промовив ці два слова,
Обернувся в другий бік,
Вийняв свого револьвера -   |
І заснув він на весь вік... | (2)','["pisni.org.ua", "cat:povstanski", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5350900'), datetime('now')),datetime('now'));
