INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_535302','Калина-Малина','Музика: народна, Тартак Слова: народні, Тартак. Виконує: Тартак, Гуляйгород','uk','ukraine_before_1917',NULL,NULL,'http://www.tartak.com.ua',NULL,'Калина-малина ні сладка, ні горка,
Ой там заплакала солдатськая жонка.
Вона заплакала, горко заридала,
Любила й кохала, в солдати й отдала.

Бути солдатом дуже непросто -
Потрібно бути високого зросту,
Щоб у формі нарядній іти на параді,
Щоб усі, хто це бачить, були справді раді!
Дуже непросто бути солдатом -
Треба тіло своє вміти замаскувати,
Тихо сидіти за густими кущами,
Зненацька почати бій з ворогами!
Раптово почати
Бій з ворогами!
Руками, ногами і, навіть, зубами
Сміливо почати бій з ворогами!
Та краще, щоб з ворогом бій починати,
Треба мати гранати та автомати.
Танки, ракети, радари, гармати,
Кораблі, літаки - усе треба мати!

Й отдала в солдати під город Варшаву,
Під город Варшаву, де б''ють барабани.
Де б''ють-вибивають, громко й вимовляють,
Розумівських хлопців в солдати приймають.

Дуже почесно бути солдатом -
На провокації не западати!
Нехай на паролі шпигун зазіхає -
Для нього солдат наш паролів не знає!
Бути солдатом дуже почесно -
На всі запитання давати відповідь чесно.
Як про медалі вдома хтось запитає -
Слід чесно казати, що медалей немає!
Немає медалей,
Медалей немає!
Якщо мама, чи тато, чи брат запитає -
Слід чесно казати, що медалей немає!
Насправді медалі не потрібні нікому,
Потрібні: подяки від воєнкому,
Значки, ордени та відпустки додому,
І крутий дизайн дембельського альбому!

За отецьким сином батько й мати плаче,
А за сиротою чорний ворон кряче.
За отецьким сином браття, браття та сестриці,
А за сиротою дівки, дівки-жалібниці.','["pisni.org.ua", "cat:rekrutski", "Рекрутські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_535302'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_535302','Калина-Малина','Калина-малина ні сладка, ні горка,
Ой там заплакала солдатськая жонка.
Вона заплакала, горко заридала,
Любила й кохала, в солдати й отдала.

Бути солдатом дуже непросто -
Потрібно бути високого зросту,
Щоб у формі нарядній іти на параді,
Щоб усі, хто це бачить, були справді раді!
Дуже непросто бути солдатом -
Треба тіло своє вміти замаскувати,
Тихо сидіти за густими кущами,
Зненацька почати бій з ворогами!
Раптово почати
Бій з ворогами!
Руками, ногами і, навіть, зубами
Сміливо почати бій з ворогами!
Та краще, щоб з ворогом бій починати,
Треба мати гранати та автомати.
Танки, ракети, радари, гармати,
Кораблі, літаки - усе треба мати!

Й отдала в солдати під город Варшаву,
Під город Варшаву, де б''ють барабани.
Де б''ють-вибивають, громко й вимовляють,
Розумівських хлопців в солдати приймають.

Дуже почесно бути солдатом -
На провокації не западати!
Нехай на паролі шпигун зазіхає -
Для нього солдат наш паролів не знає!
Бути солдатом дуже почесно -
На всі запитання давати відповідь чесно.
Як про медалі вдома хтось запитає -
Слід чесно казати, що медалей немає!
Немає медалей,
Медалей немає!
Якщо мама, чи тато, чи брат запитає -
Слід чесно казати, що медалей немає!
Насправді медалі не потрібні нікому,
Потрібні: подяки від воєнкому,
Значки, ордени та відпустки додому,
І крутий дизайн дембельського альбому!

За отецьким сином батько й мати плаче,
А за сиротою чорний ворон кряче.
За отецьким сином браття, браття та сестриці,
А за сиротою дівки, дівки-жалібниці.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_535302_l1','pisniua_535302','YouTube','https://www.youtube.com/watch?v=a-3p1bvDTNw','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5353343','Матусенько','Музика: Петро Векерик Слова: Ніна Дівіль. Виконує: Анжелiка Векерик','uk','ukraine_1991',NULL,NULL,'https://www.youtube.com/watch?v=FbLEAn3oCaE',NULL,'Той ранок бачу так, як на яву -
Духмяні вишні зацвіли в саду.
На росяну ступаючи траву,
До мами, поспішаючи, я йду!..
З гір туман спускається поволі
До підніжжя гір, щоб відпочити,
А мені назустріч йде матуся,
Щоб мене тут у саду зустріти.

Приспів:
Матусенько рідненька, дай обійму тебе,
Для мене ти, як сонце, як небо голубе!
Ти - найрідніша в світі, ріднішої нема,
Пробач, що сивиною посріблила зима...
Я дякую вам, мамо, за все, що в мене є,
За вашу ніжну ласку і за життя моє,
І за молитви ваші, що вберегли мене,
Я дякую вам, мамо, за все, за все, за все!

В пахощах садів ви сповивали,
Ніжно колискових ви співали,
В кіски запліпали срібні роси,
Де мої ходили ніжки босі.
До грудей своїх ви пригортали
І в розрадах ніжно цілували.
В Бога щастя ви мені благали,
Як ніхто про мене лиш ви дбали!

Приспів.','["pisni.org.ua", "cat:pro-batkiv", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5353343'), datetime('now')),datetime('now'));
