INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5350949','Новий рік знов йде у гості','Музика: народна Слова: Олександр Тяптін','uk','ukraine_before_1917',NULL,NULL,'авторське подання',NULL,'Новий рік знов йде у гості!
