INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5354209','Пісенька про маму','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'На зорі, на зорі
Розквітає день.
Ми у школу удвох
З мамою ідем!

Приспів:
Маму я люблю,      |
Рідну, дорогу!     |
Їй співаю пісеньку |
Лагідну таку!      | (2)

Швидко день промайнув,
Мама знов прийшла
І мене у дворі
Ніжно обняла!

Приспів.

Наймиліша від усіх
Мама для малят,
Тож про мам дорогих
Заспіваймо в лад!

Приспів.','["pisni.org.ua", "cat:dytyachi", "cat:pro-batkiv", "Дитячі пісні", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5354209'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5354209','Пісенька про маму','На зорі, на зорі
