Приспів.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_53545','Про Різдво Христово','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'народна коляда',NULL,'Про Різдво Христове
Ангел сповіщав,
Радісну та нову
Пісню заспівавав.

Всі люди радійте,     |
Тиху радість сійте    |
В день різдва святий! | (2)

Я лечу від Бога
Радість дати вам,
У вертепі в полі
Спас родився нам!

Швидко поспішайте,    |
Хлоп''ятко вітайте,    |
На землі спокій!      | (2)

Пастухи вітати
Скорше всіх прийшли,
В яслах, а не в хаті
Господа знайшли.

Стояли, співали,      |
Христа прославляли    |
За любов святу!       | (2)

Мудреці теж знали,
Де ясна зоря,
Прийшли й привітали
Бога та Царя!

Богові співали,       |
Дар Цареві склали,    |
Тішились Христу!      | (2)

Ірод, злом сповнений,
Про Ісуса взнав,
Хлоп''ятко забити
Вояків послав.

Ті дітей побили,      |
Мечі потупили,        |
А Христос все жив!    | (2)

Люди в світі жили
У гріхах своїх,
З ними до могили
Переходив гріх.

На різдво Христове    |
Дай життя чудове      |
І щасливих днів!      | (2)','["pisni.org.ua", "cat:christian", "cat:kolyadky", "Пісні на християнську тематику", "Колядки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_53545'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_53545','Про Різдво Христово','Про Різдво Христове
Ангел сповіщав,
Радісну та нову
Пісню заспівавав.

