INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5355141','Стою у лісі самотою',NULL,'uk','ukr_ssr_1919_1991',NULL,NULL,NULL,NULL,'Стою у лісі самотою,
Бачу своє рідне село.
В ріднім селі чути співають,
А в мене серденько звело...

Давно за північ, та не спиться
Снуються думи в голові
"Чи доживу я, чи побачу
Вкраїну вільну, не в ярмі?"

Стою у лісі самотою,
Бачу своє рідне село.
В ріднім селі чути співають,
А в мене серденько звело...

