INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_536848','Воротар Ворітнику розтвори Воротонька','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002',NULL,'Навпроти Двох Дівчат (А), що держаться за руки, підходить довгий ряд Дівчат (Б), що також держиться за руки і співає :
Б: Воротар-Ворітнику розтвори Воротонька !
Дві Дівчини відповідають :
А: Щож то нам за Пан їде
А: Щож то нам за Дар везе
Співає на переміну один то другий ряд і один до другого підходить :
Б: Веземо вам Дароньки йа Ранії Пчолоньки !
А: Ми того ни хочимо і за дар ни приймемо !
Б: А чогож ви хочити а чогож ви хочити ?
А: Ми хочим Зірнятонька Крайного Дитятонька !
Б: Ми того ни маємо і за Дар ни даємо !
А: Чогось нас з Гори кличут
А: А щож нам за Дар везут ?
Б: Золотеє Зернятко Крайнеє Дитинятко !
А: А в чім те Дитя бродить а в чім те Дитя ходить ?
Б: Воно ходить в Атласі і в Панянськії Красі !
Довгий ряд біжить попід руки Двох Дівчат, останню Дівчину з ряду вони задержують при собі, спускаючи перед нею руки, співають :
А: Попід Зелені Лози скачуть Дівки як Кози
А: Попід Зелені Гільці скачуть Дівки як Вівці !
І знову довгий ряд підходить. Співають від початку. Так кілька разів.','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_536848'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_536848','Воротар Ворітнику розтвори Воротонька','Навпроти Двох Дівчат (А), що держаться за руки, підходить довгий ряд Дівчат (Б), що також держиться за руки і співає :
