INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_536807','Травко Муравко чом ти ни зелена','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Символіка кузні: м''яке золото для Дівчат, золоті підківки гнуться легше, тверде залізо для Парубків:-) Гаїлки-Великдень: Українське свято Відродження Світа. Пара — любощі: Підкова. Еротика, жарти, забави. Вже Весна воскресла. Кругом Нього зелененько всередині веселенько. Благослови Мати Весну закликати. Молоді Парубочки виводили Ягілочки. Листки з приводу цієї Пісні: Коляда і Великдень: Різдво і Відродження Світа Гаїлки-Великдень: Українське Свято Відродження Світа. (Вибір Пісень) Про Українські назви місяців Марець і Май. Стежки до інших листків про Українські традиції. ВИСЛОВЛЮВАННЯ: Ци держи Віру старовіцкую? Хто Вітцевої-Матчиної Молитви не забуває Того Господь Милосердний із дна моря винімає – Дума про Олексія Поповича','Травко Муравко чом ти ни зелена
Чи тя Коні видоптали чи тя Гуси вискубали

Мине Коні ни доптали ані Гуси ни скубали
Но Молоді Паніночки виводили Ягілочки
З Чирвоними Чобітками з Золотими Підківками

Травко Муравко чом ти ни зелена
Чи тя Коні видоптали чи тя Гуси вискубали

Мине Коні ни доптали ані Гуси ни скубали
Но Молоді Парубочки виводили Ягілочки
З Великими Чобітками з Залізними  Підковами','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_536807'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_536807','Травко Муравко чом ти ни зелена','Травко Муравко чом ти ни зелена
