INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5366508','Синя смужка','Музика: ВІА Кіп''яток Слова: ВІА Кіп''яток. Виконує: ВІА Кіп''яток','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ти рішила туфлю собі зав''язати -
Я уперше в життю її зблизька побачив.
Посміхнулась мені, настрій підняла,
І не тільки його, шоби ти собі знала!

Приспів:
Синя смужка трусів на твоїй поясниці,
Жовта, чорна чи біла - всьоравно тобі личить!
Я за неї заб''ю, я її абажаю,
Як без неї я жив? Досі не знаю!
Синя смужка!..

Смайлик посеред літа, знак богині на спині,
Шось печерно-тваринне ожива в середині.
Чайка понад штанами, наші рідні Карпати,
Бачиш скільки всього про неї можна сказати?..

Приспів.

Ти у мене не перша і, мабуть, не остання,
І не знати з ким завтра прокинуся зрання.
Я забуду твої губи, груди і очі,
Та забути її я не зможу й не схочу!

Приспів.','["pisni.org.ua", "cat:zhartivlyvi", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5366508'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5366508','Синя смужка','Ти рішила туфлю собі зав''язати -
Я уперше в життю її зблизька побачив.
Посміхнулась мені, настрій підняла,
І не тільки його, шоби ти собі знала!

Приспів:
Синя смужка трусів на твоїй поясниці,
Жовта, чорна чи біла - всьоравно тобі личить!
Я за неї заб''ю, я її абажаю,
Як без неї я жив? Досі не знаю!
Синя смужка!..

Смайлик посеред літа, знак богині на спині,
Шось печерно-тваринне ожива в середині.
Чайка понад штанами, наші рідні Карпати,
Бачиш скільки всього про неї можна сказати?..

Приспів.

Ти у мене не перша і, мабуть, не остання,
І не знати з ким завтра прокинуся зрання.
Я забуду твої губи, груди і очі,
Та забути її я не зможу й не схочу!

Приспів.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_5366508_l1','pisniua_5366508','YouTube','https://www.youtube.com/watch?v=GT74WlNDsg0','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5374040','У лісі, у темному','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1930','аудіозапис','Місце побутування: смт Запитів, Кам''янка-Бузький район, Львівська область. Респондент: Максимишин Марія Олексіївна, 1930 р.н. Збирачі: Вовчак Андрій, Мартиник Соломія.','У лісі, у темному,
Серед пахучих трав
Лежить козак ранений,
Лежить, неначе спав.

І ліки прикладають
Його вірні друзі,
І кров йому гамують,
А він неначе в сні.

Все тихше, тихше, тихше
В козака серце б''є,
І нічка вже минає,
А день вже настає.

В неділю ранесенько,
Як почало світать,
Біжить якась дівчина,
Біжить вона до нас.

Біжить вона стежкою,
А кулі наче град,
Біжить вона стежкою,
Не подається взад.

Прибігла до милого
Та й стала говорить:
Ох, милий, серце моє,
Що ж тебе болить?

Болить мене, кохана,
Болить права рука,
Ранила гостра куля,
Куля ворожая!

У лісі, у темному,
Де ворон закричав,
Заплакала дівчина,
Як милий умирав.

Від вітру почорніло
Козацькеє тіло,
І кров''ю закипіло
Його біле чоло.','["pisni.org.ua", "cat:strilecki", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5374040'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5374040','У лісі, у темному','У лісі, у темному,
