INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_537405','Ой йшла Дівка через Двір','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Народні пісні в записах Степана Руданського. - К.: Музична Україна, 1972','За автографом: Відділ рукописів Інституту літератури ім. Т.Г.Шевченка АН УРСР, архів С.Руданського, ф. 63, од. зб. 2. - Народные малороссийские песни, собранные в Подольской губернии С.В.Р. Т.2. Пісні козацькії, чумацькії, бурлацькії, рекрутськії, весільнії, великоднії і так собі. Пісні великоднії, N 3. Гаївки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Десь узялася Молода Дівчина. Стала ж Вона сяяти. Стала ж Вона сяяти стала Діброва палати. Кілько в Цебрі Води є тілько в Дівках Правди є. А ми Йому Кінця не знайдем. Листки з приводу цієї Пісні: Вербний Тиждень і Шутка. Про Українські назви місяців Марець і Май. Коляда і Великдень: Різдво і Відродження Світа Гаїлки-Великдень — Українське Свято Відродження Світа. (Вибір Пісень)','Ой йшла Дівка через Двір
На Ній Сукня в Дев''ять Піл
Стала ж Вона сяяти
Стала Діброва палати
Стали Хлопці гасити
Решетом Воду носити
Кілько в Решеті Води є
Тілько в Хлопцях Правди є !

Ой йшла Дівка через Двір
На Ній Сукня в Дев''ять Піл
Стала ж Вона сяяти
Стала Діброва палати
Стали Мужі гасити
Ситом Воду носити
Кілько в Ситі Води є
Тілько в Мужах Правди є !

