INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5372848','Учать в школі','Музика: Володимир Шаїнський Слова: Михайло Пляцковський','uk','ukraine_1991',NULL,NULL,'http://composer.ucoz.ua/load/vchat_u_shkoli/5-1-0-223',NULL,'Буквам різним дати лад,
