INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5374003','Повіяв вітер по степу','Українська народна пісня','uk','ukrainian_peoples_republic_1917_1921',NULL,'1921','аудіозапис','Місце побутування: с. Бережок, Лімнянська сільрада, Турківський район, Львівська область. Респондент: Іскович Анастасія Якимівна, 1921 р.н. Збирачі: Беднарська Ружена, Іванищук Марія.','Повіяв вітер по степу,
Трава ся похилила,
Впав в бою молодий козак,
Дівчина затужила...

Ото був хлопець молодий,
Пора йому було кохати.
Він впав, як той сухий листок,
Та й буде він лежати...

Дівчина вийшла на могилу,
Могила ся втворила
І слава по світі лунала,
Що любов була щира...','["pisni.org.ua", "cat:strilecki", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5374003'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5374003','Повіяв вітер по степу','Повіяв вітер по степу,
