INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5371900','Ти віддай все в руки Бога',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує Дарина Кочанжи.','Він буде вічно любити тебе,
Блакитне небо в твоїх очах.
Він бачить розпач твій та твій страх,
Ти віддай всі турботу Йому!

Приспів:
Ти віддай все в руки Бога,
Всі печалі й страхи свої!
Він - надія, він - допомога,
В Ньому спокій твоїй душі!

І коли в тебе немає сил,
Ти хворе серце Йому неси!
Твою молитву почує Він,
Понесе у долонях Своїх!

Приспів.','["pisni.org.ua", "cat:christian", "Пісні на християнську тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5371900'), datetime('now')),datetime('now'));
