INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5374601','Засіяла зірка на Сході',NULL,'uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Засіяла зірка на Сході,
Сяйвом все навкруг освітила,
І настала радість в народі:
Марія Христа народила!

Приспів:
Народився Спас!
Народився Спас
На спасіння кожній душі!
Він спасе всіх нас!
Він спасе всіх нас!
Поклонімося Йому всі!

Перед Ним царі дари ставлять,
Мудреці ідуть вже до Нього!
І ангели всі Його славлять,
Як Дитятко Бога Живого!

Приспів.

А Ірод лихий та заклятий,
Як почув про цю новину,
Наказав дітей убивати,
Щоб звести Дитину Святу.

Приспів.

Та Отець Його, Вседержитель
Збереже від смерті Дитя.
Вічно Цар Ісус буде жити,
Всім покаже правду життя.

Приспів.

Засіяла зірка на Сході!','["pisni.org.ua", "cat:kolyadky", "cat:shchedrivky", "cat:suchasni-pisni-rizdvo", "Колядки", "Щедрівки", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5374601'), datetime('now')),datetime('now'));
