INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_537444','В Царіграді на Риночку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Українські релігійні роздуми про Спасіння © Видавництво „Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2003','Воскресна: світ не по Правді. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Ой Ми зіслані на признаванє. Нема в світі Правди не зіскати. Байді Молодому Мед-горілку пити. Та чи будеш мені вірнесенький. Листки з приводу цієї Пісні: Коляда і Великдень: Різдво і Відродження Світа. Гаїлковий Білоданчик і Первісний Молодець-Стрілець Українські реліґійні роздуми про Неволю та Спасіння Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до листків про Українські традиції.','В Царіграді на Риночку
Та п''є Байда Мед-горілочку
Ой п''є Байда та не день не два
Не одну нічку тай не годиночку
Ой п''є Байда тай кивається
Та на свого Цюру поглядається

Ой Цюро-ж мій молоденький
Та чи будеш мені вірнесенький

Цар Турецький к нему присилає
Байду к собі підмовляє
Ой ти Байдо та славнесенький
Будь мені лицар та вірнесенький
Возьми в мене Царівночку
Будеш паном на всю Вкраїночку

Твоя Царю віра проклятая
Твоя Царівночка поганая

Ой крикнув Цар на свої гайдуки
Возьміть Байду добре в руки
На гак ребром зачепіте

Ой висить Байда тай не день не два
Не одну нічку тай не годиночку
Ой висить Байда тай гадає
Та на свого Цюру споглядає
Та на свого Цюру молодого
І на свого Коня Вороного

Ой Цюро-ж мій молоденький
Подай мені Лучок та Тугесенький
Подай мені Тугий Лучок
І Стрілочок цілий пучок

Ой бачу я Три Голубочки,
Хочу я убити для його Дочки
Де я мірю там я вцілю
Де я важу там я вражу

Ой як стрілив Царя вцілив
А Царицю в потилицю
Його Доньку в головоньку

От то-ж тобі Царю за Байдину кару
Було тобі знати як Байду карати
Було Байді голову ізтяти
Його тіло поховати
Вороним конем їздити
Хлопця собі зголубити','["pisni.org.ua", "cat:dumy", "cat:kozacki", "Думи", "Козацькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_537444'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_537444','В Царіграді на Риночку','В Царіграді на Риночку
