INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5363508','Сім''я','Музика: Володимир Будейчук Слова: Ірина Зінковська. Виконує: Тетяна Піскарьова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'В короні зір і у віночку з жита
Малює ніч на синім полотні,
Щаслива я, бо чоловік і діти -
Найбільший дар від Господа мені!
Зігріє вдома доня ніжним словом
І син пригорне лагідним крилом,
В сім''ї завжди я під святим покровом,
З любов''ю, миром, щастям і теплом!

Приспів:
Сім''я - це пісня і життя!
Сім''я - землі серцебиття!
Сім''я - дитячий щирий сміх!
Навіки бережіть близьких!..
Сім''я - це вірність і любов!
Сім''я - це святість молитов!
Сім''я незламна, як твердиня,
Мого народу берегиня!

Коханий мій, коли мені не легко,
Твоя любов за руку поведе!..
Як два птахи, ми - вірні, мов лелеки,
Мій рідний, в тебе серце золоте!
Одна на віки в мене Батьківщина,
Земля, омита хвилями Дніпра,
Одна в моєму серці Україна
Горить, як символ єдності й добра!

Приспів.','["pisni.org.ua", "cat:pro-batkiv", "cat:pro-ditey", "Пісні про любов до батьків", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5363508'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5363508','Сім''я','В короні зір і у віночку з жита
