INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5377900','Я прошу тебе, Ісусе',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я прошу тебе, Ісусе,
Не лишай мене в біді,
Бо душа на волю рветься
У важкій тій самоті...
Серце крається на двоє,
Біль і страх в мені живе,
А Христос так промовляє:
Не журися, все мине!

Приспів:
Я візьму тебе на руки, |
Понесу туди, де Я -    |
І не буде вже розлуки, |
Бо дитина - ти - Моя!  | (2)

В мені сумніви бувають,
Недовіра ще живе,
Біль і смуток посилають -
І обличчя знов сумне...
Сльози котяться рікою
І в душі ще все пече,
А Христос так промовляє:
Не журися, все мине!

Приспів.','["pisni.org.ua", "cat:christian", "cat:strasni", "Пісні на християнську тематику", "Страсні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5377900'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5377900','Я прошу тебе, Ісусе','Я прошу тебе, Ісусе,
Не лишай мене в біді,
Бо душа на волю рветься
У важкій тій самоті...
Серце крається на двоє,
Біль і страх в мені живе,
А Христос так промовляє:
Не журися, все мине!

Приспів:
Я візьму тебе на руки, |
Понесу туди, де Я -    |
І не буде вже розлуки, |
Бо дитина - ти - Моя!  | (2)

В мені сумніви бувають,
Недовіра ще живе,
Біль і смуток посилають -
І обличчя знов сумне...
Сльози котяться рікою
І в душі ще все пече,
А Христос так промовляє:
Не журися, все мине!

Приспів.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_5377900_l1','pisniua_5377900','YouTube','https://www.youtube.com/watch?v=fMdXEOaEkF8','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5375242','Сумно, сумно сонце сходить',NULL,'uk','ukr_ssr_1919_1991',NULL,NULL,'аудіозапис','Місце побутування: с. Вовче, Вовченська сільрада, Турківський район, Львівська область. Респондент: Музика Єва Василівна. Збирачі: Кльок Юлія, Винницька Ліля.','Сумно, сумно сонце сходить
В українському селі,
Покидають усі села -
Усі хлопці молоді.

Покинув я рідну хату,
Покинув я родину,
А сам пішов в темнім лісі
Пошукати хатину.

В тій хатині дуже сумно,
Бо без дверей, без вікна,
Вивезли в Сибір родину,
Сам остався сирота.

Ой, пішов я, шукаючи,
По тих дебрях лісових,
Сумна доля нас спіткала
Усіх хлопців молодих.','["pisni.org.ua", "cat:povstanski", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5375242'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5375242','Сумно, сумно сонце сходить','Сумно, сумно сонце сходить
