INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5379704','Школярики-школярі','Музика: Таїсія Шутенко Слова: Лідія Марунич','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Дружно ми зростали
В дитсадку своїм,
Вже дорослі стали:
Нам усім — по сім!

Приспів:
Кличе дзвоник всіх у клас,
Приготуймо букварі!
Називають нас, називають нас
Школярики—школярі!

Ранок вже нас будить,
Світлий, голубий!
Школо, рідна, люба,
Двері нам відкрий!

Приспів.','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5379704'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5379704','Школярики-школярі','Дружно ми зростали
