INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5375209','Рано-раненько навесні в зеленому гаю',NULL,'uk','ukr_ssr_1919_1991',NULL,NULL,'аудіозапис','Місце побутування: смт Запитів, Кам''янка-Бузький район, Львівська область. Респондент: Максимишин Марія Олексіївна. Збирачі: Вовчак Андрій, Мартиник Соломія.','Рано-раненько навесні
В зеленому гаю
Зібрались хлопці молоді,
Зібрались до бою,
Бо ворог всюди наступав,
Він наших хлопців убивав.
Хлопці ішли на смерть страшну
За Вкраїну вільну!

Но ворог лютий і страшний,
Озброєн до зубів,
Побив повстанців молодих,
Нікого не жалів.
Ніхто не бачив тих знущань,
Ніхто не знає тих страждань -
Єсть в лісі сосни і дуби,
І пташки навкруги.

Вони вмирали, як герої,
Не здались ворогам,
Їх тіло кулі шматували,
Вони прощалися з життям.
А на очах була сльоза,
Бо в домі матінка стара,
І не діждеться його мила,
Не знає де могила...','["pisni.org.ua", "cat:povstanski", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5375209'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5375209','Рано-раненько навесні в зеленому гаю','Рано-раненько навесні
В зеленому гаю
Зібрались хлопці молоді,
Зібрались до бою,
Бо ворог всюди наступав,
Він наших хлопців убивав.
Хлопці ішли на смерть страшну
За Вкраїну вільну!

Но ворог лютий і страшний,
Озброєн до зубів,
Побив повстанців молодих,
Нікого не жалів.
Ніхто не бачив тих знущань,
Ніхто не знає тих страждань -
Єсть в лісі сосни і дуби,
І пташки навкруги.

Вони вмирали, як герої,
Не здались ворогам,
Їх тіло кулі шматували,
Вони прощалися з життям.
А на очах була сльоза,
Бо в домі матінка стара,
І не діждеться його мила,
Не знає де могила...');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_537747','Гей на Чорному Морі та на Камені Біленькому','(Про Олексія-поповича та Вітцеву-Матчину Молитву). Виконує: Микола Будник','uk','ukraine_before_1917',NULL,NULL,'Українські релігійні роздуми про Спасіння © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2003','Українські реліґійні роздуми про Воскресіння, Неволю і Спасіння. Пісні Великодні — Спасительні: світ не по Правді. Пісні-плачі Сокола-Прадіда. Пісенною Парою Марусі-попівні — Олексій-попович. Попович — син Попа? того Єдиного, що служить, як співають Колядки, Службу Божу людям у Церкві-Всесвіті? Ой Ми зіслані на Признаванє. Нема в світі Правди не зіскати. Що хто Вітцевої-Матчиної Молитви не забуває Того Господь Милосердний із Дна Моря винімає А десь ми поверх всякої міри гріха набрали. Да ще ж хотілось швидше здобичі набірати. Гей на Чорному Морі та на Камені Біленькому Ой то не Пили то пилили Питається Дніпр Тихого Дуная Гомін гомін гомін по діброві... Галагани (Ґалаґани)... Носи... Ей то се Брат не Сопротивна Хвиля затопляє. На Синьому Морі на Білому Камені сидить Сокіл Ясен Ой на Чорному Морі на Білому Камені Не єсть це нас Шабля Турецькая рубала. Гей усі Поля Самарські почорніли Ой всі Поля Самарськиї позоряли Ой то не Пили то пилили Стали Отцеву-й-ненчину Молитву забувати. А не в Бору Сосна зашуміла У Святую Неділю як Та Бідна Вдова То ж вони Темний Похорон одправляли. Ой то не Пили то пилили І усіх вас Невольників із Темниці випускати. Голосна та Правдива як Господа слово. Листки з приводу цієї Пісні: Українські реліґійні пісні-роздуми про Неволю та Спасіння. Плач Сокола. Традиції Батька. Коляда і Великдень: Різдво і Відродження Світа. Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Висловлювання: Од Бога і Голос той і ті Слова. Ну що б здавалося слова... Слова та голос більш нічого. А серце б''ється ожива, Як їх почує!.. Знать — од Бога І Голос той і ті Слова Ідуть між люди! — Тарас Шевченко Рокове Коло. Стежки до листків про Українські традиції. Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда)... Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі) ― Весілля: Дівич-Вечір... Великдень... Зелені Свята (Трійця) ― Царинні Містерії... Івана Купала... Астральні Жнива... Рокове Коло. Староукраїнська культура й реліґія приявлюється в давніх передхристиянських святах — реліґійних, господарських і побутових, що досі тривають в Українського народу в зв''язаних зі Святочними часами народних піснях і в уривках давніх обрядів. Хоч зараз велика частина Українського народу, — особливо нове покоління, що виросло на повоєнних руїнах, — не здає собі справи з провідних думок цих Свят, але інтуіційно відчуває повагу і святість давніх традицій. І все-таки увесь нарід держиться досі старовіцьких Святочних звичаїв і поведінок. Сю інтуіційну свідомість чогось величного й Святого, переказаного предками і зв''язаного зі старовіцькими обрядами, піддержують злучені з Святочним часом пісні, — ось як: Колядки, Щедрівки, Гаївки і т. д., — і в них-то найбільше міститься народних традицій, як реліґійних, так господарських і суспільних, поданих у мітичному вигляді....Відтворити з тих традицій образ давньої Української віри і культури. Ця віра триває досі, хоч не є висловлена догматично, а давня Українська культура є в основах сучасного життя народу. Нарід жиє старими ідеями — а інтеліґенція народна переходить над ними до порядку денного, не здаючи собі справи з їх культурної ціни і сили, не розуміючи психіки народу і будучи в постійній з ним дисгармонії; не цінить культурного давнього дорібку, який мав колись свою стійність і міг би бути вихіснуваним і сьогодня, хоч інші зараз життєві й культурні обставини й поняття. (Кс. Сосенко)','Гей на Чорному Морі
Та на Камені Біленькому
Там сидів Сокіл Ясненький
Ой жалібненько квилить-проквиляє
Да на Чорнеє Море спильна поглядає
А що на Чорному Морі щось не Добреє починає

Зла Супротивна Хвилечная Хвиля вставає
Судна Козацькії-молодецькії на Три Часті розбиває-гей

Що Первую часть ухопило в Дунайськеє Гирло забило
А Другую часть ухопило
В Турецькую Землю занесло
А Третяя часть і тут має посеред самого Чорного Моря потопає-гей

Та при тій же Третій часті війська
Був Старшиною Грицько Коломийченко
По всему Військові козацькому ість барзе покличе
То ж то він Добре дбає на чердаки зіходжає
До Козацького війська Словами промовляє

Гей Козаки-панове
Брати-мої
Запорожці
Ой не є це так Чорнеє Море розіграло
А десь ми поверх всякої міри гріха набрали-гей

Ой же ж сповідайтеся ви Панове-козаки
Господові Милосердному
І Чорному Морю
І мені Отаманові Кошовому
І один одному
І перед усім Військом

Козаки теє зачували
Дай усі замовчали

Обізветься тільки Олексій-попович
Славний Лицар
Войськовий Писар

Гей Панове-козаки
Це ж ви мене Олексія-поповича
У рученьки возьміть
І самого ж мене у Чорнеє Море іспустіть

А Козаки
Слова Олексія-поповича зачували
Та до нього
До Писаря Войськового
До Славного Лицаря
Словами промовляли

Гей Олексію-поповичу
Як же ж ти гріха більш од нас маєш
Ти ж нам Святеє Писаніє потричі на день читаєш

А Олексій-попович теє зачував
Та перед лиця
Світлого всього Війська козацького
Гріхи свої по Чистій Правді сповідав
Наперід Господові Милосердному
І Отаманові Кошовому

Ой Панове-козаки
Брати-мої-сердешнії
Як же ж я в Охотнеє Військо від''їжджав
У Отця-матусі Прощення
Не брав

Старшого брата за брата не мав
Меншу сестру з города
Стременем
У груди
Одпіхав

А як я шляхами України проїжджав
То своїм вороним конем
Гурти і діточок наїжджав
А матері із ворітечок вибігали
Діточок на рученьки брали
Мене
Олексія-поповича
Кляли-проклинали-гей

Як я
Мимо Божих церков проїжджав
Зі своєї голови
Шапки на скидав
Та на себе хреснеє знамення не накладав

А ви питаєте
Чи не
Гріха я
Набирав

А ше найгірший гріх мене спіткав як я в Охотне військо прибував
Старшим козакам Добрий День не казав
І з Празником не поздоровляв

Да якби тото тільки
Бо тож то коли Військо козацькеє споряджали я своїм голосом
Повелів
В Недобрий час
Чаєчки козацькії на Чорнеє Море спускати
Да ще ж хотілось швидше здобичі
Набірати
Да поперед іншими козаками
Силою вихвалятись
Тож то ми чи в Добрую годину
Тей Похід козацький починали

Ох як тільки ж почав Олексій-попович по Чистій Правді перед Господом Милосердним
Чорним Морем
Отаманом Виборним Войськовим
Да перед лицем усього Війська козацького
Гріхи свої по Чистій Правді сповідати
Чорне Море стало затихати
Затихало
Затихало ніби на ньому й Бурі ніколи не було

Тоді то всі Козаки
На Чаєчках на своїх
До Острова Тендора підпливали
Тоді то всі Козаки
Ні єдиного не втерявши на Крутий Берег зіходили

Тоді то Олексій-попович
Добре Звичаї Козацькії знавши
До рук до своїх
Святеє Писаніє
Брав
Дай отак
До Козаків
Словами промовляв
Гей Панове-козаки
Слухайте
І розумійте що в Святім Писанії
Сказано

Що хто Вітцевої-Матчиної Молитви не забуває
Того Господь Милосердний із Дна Моря винімає

Нам годицця Теє спом''ятати
За которими Молитвами
Стали ми Хліба-соли поживати

Славная голова
Олексій-попович
Не по книжках мудрості набирав
Свої гріхи
По Чистій Правді
Перед Господом Милосердним і всіми нами  сповідав
І так то він
Доумів що
Доброї години треба в Старших Людей питати
Добре діло треба починати
Із малого кроку
Старшим людям Добрий День казати
Шапочку знімати
З Празником поздоровляти

Дай Боже вам
Мирові християнському народові царському
Од сьогодні всім на здравіє щасливії літа до кіньця віка
Слава Козацькая не вмре не пропаде
Дай Боже    Заспів (mp3)  (','["pisni.org.ua", "cat:dumy", "cat:kozacki", "cat:socialno-pobutovi", "cat:suspilno-politychni", "Думи", "Козацькі пісні", "Соціально-побутові пісні", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_537747'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_537747','Гей на Чорному Морі та на Камені Біленькому','Гей на Чорному Морі
Та на Камені Біленькому
Там сидів Сокіл Ясненький
Ой жалібненько квилить-проквиляє
Да на Чорнеє Море спильна поглядає
А що на Чорному Морі щось не Добреє починає

Зла Супротивна Хвилечная Хвиля вставає
Судна Козацькії-молодецькії на Три Часті розбиває-гей

Що Первую часть ухопило в Дунайськеє Гирло забило
А Другую часть ухопило
В Турецькую Землю занесло
А Третяя часть і тут має посеред самого Чорного Моря потопає-гей

Та при тій же Третій часті війська
Був Старшиною Грицько Коломийченко
По всему Військові козацькому ість барзе покличе
То ж то він Добре дбає на чердаки зіходжає
До Козацького війська Словами промовляє

Гей Козаки-панове
Брати-мої
Запорожці
Ой не є це так Чорнеє Море розіграло
А десь ми поверх всякої міри гріха набрали-гей

Ой же ж сповідайтеся ви Панове-козаки
Господові Милосердному
І Чорному Морю
І мені Отаманові Кошовому
І один одному
І перед усім Військом

Козаки теє зачували
