INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5376106','Пісня про Героїв Крут','Музика: Олександр Шевченко Слова: Олександр Шевченко','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'https://www.youtube.com/watch?v=8vE-IbUBorw','Художній і музичний керівник - Наталя Самсонова. Солісти - старший віце-сержант Андрій Стефунька, ліцеїсти Олег Кузьмін, Андрій Холстинін. За сприяння телеканалу "Перший західний". Пісню виконують ліцеїсти ліцею імені Героїв Крут.','Треба пам''ятати, не забути
Всі навали хижих чужаків,
Курені студентські йшли на Крути,
Правнуки славетних козаків.
Їм сікли в обличчя сніговії,
Хмарились, чорніли небеса,
За плечима був не просто Київ,
За плечима - Україна вся!

Приспів:
Перед ведуть, ведуть Герої Крут,
У безсмертя лежить їх путь!
Перед ведуть, ведуть Герої Крут,
Через пам''ять мою ідуть!

Вороги повсюди виростали,
Молода держава - у вогні,
Україна по неволі стала
Жертвою московської брехні!
А вони взяли́ у руки зброю,
Кожен з них не хлопчик вже, а - муж!
Вклонимося мужності Героїв,
Серед них - ці 300 юних душ!..

Приспів.

Ми тепер - нащадки тих Героїв,
Нам тепер Вітчизну боронить,
Крокувати до мети святої
І не завагатись ні на мить!
Імена ми їхні пам''ятаєм,
І несемо їх на прапорах,
Їхню славу знову підіймаєм,
Грізну славу ворогам на страх!

Приспів.','["pisni.org.ua", "cat:devoted", "cat:kruty", "Пісні присвячені окремим особам", "Пісні пам''яті Героїв бою під Крутами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5376106'), datetime('now')),datetime('now'));
