Нам неодмінно пощастить!

Приспів.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5383302','Човен','Музика: Святослав Вакарчук Слова: Святослав Вакарчук. Виконує: Гурт "Океан Ельзи"','uk','ukraine_1991',NULL,NULL,'аудіозапис; акорди - MuseTANG https://www.youtube.com/watch?v=fFkWH7qCZI8',NULL,'Човен,
Мій маленький човен
Хвилями гойдає
Пам''ять день і ніч...
Човен
Спогадами повен,
З нього добре видно
Землю навсібіч...
Там зліва і справа
Цвітуть сади...
Там зліва і справа
Чужі сліди...
