INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_538949','Ой на Городі Широка Квітка','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004. 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пара - любощі: Город. Широка Квітка. Іваньо-Марійка. Вибір Пари. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. Хто Її вирвав Марійка Дівка. А на тій Вербі Рожеві Квіти. Буде тобі Квітка Красна. Були Світилки Яснії Зірки. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','Ой на Городі Широка Квітка
Хто Її вирвав Марійка Дівка

Марійка Дівка тай Невеличка
Сватай Іваньо Перепеличка','["pisni.org.ua", "cat:kupalski", "Купальські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_538949'), datetime('now')),datetime('now'));
