INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_539545','Ой люлі, налетіли гулі','Слова: Микола Сингаївський','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Ой люлі, ой люлі, налетіли гулі.
