INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5398003','Марія - Мати всім',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Марія - Мати всім,
Небесна брамо у небесний храм,
Ти веди до Ісуса, Отця.
Ти Мати бідним! Ти Мати нам!

Приспів:
Благословенна Ти,
Збережи нас від зла і марноти.
Мати світла, Ти Цариця всіх -
І на землі, і на небесах!

Огорни плащем
І дітей збережи своїм теплом,
Мати світла, Мати доброти,
Ти нас від злого в світі захисти.

Приспів.

Матінко моя,
У Твоїх руках моя сім''я.
Огорни любов''ю усіх нас,
Щоб прославляли Бога в небесах.

Приспів.','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5398003'), datetime('now')),datetime('now'));
