Приспів.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_5403141_l1','pisniua_5403141','YouTube','https://www.youtube.com/watch?v=3dJxRL521kI','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5405848','Світ немов кольоровий луг','Музика: Володимир Шаїнський Слова: Михайло Пляцковський','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Вітер хмаринки у небі
Несе там, там, там...
Дружба в житті пригодиться
Усім нам, нам, нам!

Приспів:
Світ немов кольоровий луг,
Коли поруч з тобою друг!
Наче сонячна вся земля,
Міцна дружба на все життя!

Музика друзів збирає усіх
В круг, в круг, в круг!
День буде сонячним поруч,
Коли друг, друг, друг!

Приспів.

Друг допоможе і буде завжди
Рад, рад, рад!
З другом і труднощі легше
Пройти так, так, так!

Приспів.','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5405848'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5405848','Світ немов кольоровий луг','Вітер хмаринки у небі
Несе там, там, там...
