INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5387848','Емігрант','Музика: Віктор Винник Слова: Віктор Винник. Виконує: Мері','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Сльози не поможуть,
Сльози просто вода
Тим більше знаєш
Коли, з ким і куда
Скоро красивий літак
Зі сріблястим крилом
Віднесе тебе далеко,
Далеко від дому...
Там буде значно краще,
Буде все не так
І трава зеленіша,
Хліб інакший на смак...
Та ти не думаєш про це,
Слухаєш тишу, не спиш,
Тільки Бог напевно знає,
Про що ти мовчиш...

Приспів:
І остання ніч
Плаче за вікном,
Де усе знайоме...
Де любив і ріс
Де ходив малим,
Все, що кликав домом...
Душу спогади
Спалюють вогнем,
Б''ють по серцю кантом,
Завтра встанеш ти, брат...

І ти нікуди не тікаєш,
Ти просто ідеш,
Бо сам ніколи не знаєш,
Де загубиш, знайдеш.
Щоб не ходити по колу,
Не дивитись на то саме,
Тебе вже не зупинять,
Навіть, сльози мами...
І щоб не бачити з екрану
Знайомих облич,
Які розказують як жити,
Знають в чому річ,
Їм не важливо хто ти,
Нецікаво де ти,
Вони давно живуть
На своїх власних планетах...
Ти закриваєш очі,
Ти рахуєш хвилини,
Ти вже нічого не хочеш,
Ніхто ні в чому не винен,
І ти не думаєш про це,
Слухаєш тишу, не спиш
І тільки Бог напевно знає,
Про що ти мовчиш...

Приспів. (2)','["pisni.org.ua", "cat:emigration", "Пісні про еміґрацію"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5387848'), datetime('now')),datetime('now'));
