INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5397141','В горах грім гуде','Музика: Осип Маковей, Дмитро Котко Слова: Осип Маковей','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'Сайт "Наше (тексти пісень) nashe.cjv.ua/song/16316','Музична інтерпретація для змішаного хору, підбір акордів, комп''ютерне відтворення.','В горах грім гуде, хоч зима паде,
Землю спороли гармати,
Гримить війна, дуднить луна,     |
Дрожать ранені карпати.          | (2)

Хто живий, вставай боронити край,
Вкритий огнем і мерцями,
Не буле тобі сумно у борбі       |
Між Січовими Стрільцями.         | (2)

Лютий кат прийшов проливати кров,
Взяти народ наш в неволю.
І море сліз у край приніс,       |
Розбій і смерть і недолю.        | (2)

Та вступився кат із верхів Карпат,
Втік, наче вовк, манівцями,
Або тут впав, як у бій попав     |
Із Січовими Стрільцями.          | (2)

Січові Стрільці за свій край борці,
І за рідню, за свободу,
Для них борба - се їх журба      |
І дорогого народу.               | (2)

І ряди могил не візьмуть їх сил,
Ворог тут б''ється з серцями,
Лицаря уб''є, думка ожиє          |
Між Січовими Стрільцями.         | (2)

Хто ж бо там іде і перед веде?
Диво! Се наші дівчата!
Личко, як мак! Кругом козак -    |
Душа стрілецька завзята.         | (2)

Не цілуйте їх! На війні це гріх,
Ви уберіть їх вінцями!
Слава тим дочкам, щирим козачкам |
Між Січовими Стрільцями.         | (2)    комп''ютерне відтворення','["pisni.org.ua", "cat:strilecki", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5397141'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5397141','В горах грім гуде','В горах грім гуде, хоч зима паде,
Землю спороли гармати,
Гримить війна, дуднить луна,     |
Дрожать ранені карпати.          | (2)

Хто живий, вставай боронити край,
Вкритий огнем і мерцями,
Не буле тобі сумно у борбі       |
Між Січовими Стрільцями.         | (2)

Лютий кат прийшов проливати кров,
Взяти народ наш в неволю.
І море сліз у край приніс,       |
Розбій і смерть і недолю.        | (2)

Та вступився кат із верхів Карпат,
Втік, наче вовк, манівцями,
Або тут впав, як у бій попав     |
Із Січовими Стрільцями.          | (2)

Січові Стрільці за свій край борці,
І за рідню, за свободу,
Для них борба - се їх журба      |
І дорогого народу.               | (2)

І ряди могил не візьмуть їх сил,
Ворог тут б''ється з серцями,
Лицаря уб''є, думка ожиє          |
Між Січовими Стрільцями.         | (2)

Хто ж бо там іде і перед веде?
Диво! Се наші дівчата!
Личко, як мак! Кругом козак -    |
Душа стрілецька завзята.         | (2)

Не цілуйте їх! На війні це гріх,
Ви уберіть їх вінцями!
Слава тим дочкам, щирим козачкам |
Між Січовими Стрільцями.         | (2)    комп''ютерне відтворення');
