INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_542508','Мама Марія','Музика: Павло Дворський Слова: Михайло Ткач. Виконує: Тріо Мареничів, Антоніна Маренич, Тарас Петриненко, Тріо Либідь, Павло Дворський','uk','ukraine_1991',NULL,NULL,'Альбом Тріо Мареничів "Ой під вишнею"',NULL,'Зачинаю свій день з дорогого ім''я,
Воно як сподівана мрія,
Як хлібові й сонцю молитва моя -      |
Мама-Марія, мама-Марія.               | (2)

Чую кличеш мене, як виходиш на шлях,
Чоло сподіванням зоріє,
А літо достигле шепоче в полях:       |
Мама-Марія, мама-Марія.               | (2)

Бачу сиву тебе, берегиню свою,
В очах від Мадонни замрія...
В любові і слові тебе впізнаю,        |
Мама-Марія, мама-Марія.               | (2)

Так я змалку мене понесла в сповитку
Туди де в тумані надія,
Весь вік мою долю несе нелегку        |
Мама-Марія, мама-Марія.               | (2)

Всі горби перейду, хоч важка крутизна
Спочину на вищій горі я,
І в білому світі повторить луна
Мама-Марія, мама-Марія.
І в білому світі повторить луна
Мама-Марія, Аве Марія...','["pisni.org.ua", "cat:pro-batkiv", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_542508'), datetime('now')),datetime('now'));
