INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5426209','Володя плюс Ірина','Музика: Ольга Монастирська Слова: Ольга Монастирська. Виконує: Ольга Монастирська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Стій, зачекай, і не біжи,
Не біжи, мить, так швидко,
А ти, не тримай, а відпусти -
Нехай прийде нове літо!
Ось і вже час, коли ми знову
Зібрались, як ніколи,
В той самий клас, за двадцять
Років після школи.

Приспів:
А пам''ятаєш, пам''ятаєш,
Часи були такі ще класні?
А пам''ятаєш, пам''ятаєш,
Як ми були в одному класі?
Я пам''ятаю, як сердитою була
Від того, що на стінах.
Роки минули та лишилися слова:
Володя плюс Ірина!
Володя плюс Ірина!

Час пролетів: в когось кар''єра,
А в когось маленькі діти,
А хтось загубив своє кохання
І правди нікуди діти,
Та все ж ми разом, як і колись
Зібрались в дружньому колі,
І ти сам прийшов, чи це ілюзія,
Чи насправді доля?.. Насправді доля?..

Приспів.

А пам''ятаєш?..

Приспів.

Володя плюс Ірина!','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5426209'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5426209','Володя плюс Ірина','Стій, зачекай, і не біжи,
