INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5430141','На моїй землі','Музика: Кирило Булкін','uk','ukraine_1991',NULL,'2021','Літопис авторської пісні України №38 (684) 2021 рік.',NULL,'На моїй землі - влада темряви,
Шабаш нечисти, час пітьми.
Ворог виміряв, що я вимріяв,
Й топче чорними чобітьми.

Не навік, однак, укарбовані
В степ і ліс чужинські сліди...
Лину в ґрунт дощем, змию знак біди
На моїй землі окупованій.

Рев чужих пісень замість солов''їв -
Де той звук, щоб з ним сперечавсь?
Щоби кулемет своє соло вів -
Вже не час, а мо'', ще не час.

У льохи й під стріхи захований,
Арсенал чекає часу,
Як пихатих зайд знайде правий суд
На моїй землі окупованій.

Мережі нема. Сам за себе дій.
Та чи вдієш щось, коли сам?
Браття з сестрами, наче лебеді,
Клином рушили в небеса.

Хто на Сході впав, замордований,
Хто на Захід вирвався й зник...
Лиш відлунням крук відповість на крик
На моїй землі окупованій.

Тануть в присмерку краю обриси,
Розчинюсь до ранку і я -
Щоб приміряти, в іншім образі,
Іншу тактику та ім''я.

Щоб вести в реальності зміненій
В інший спосіб - той самий бій:
За життя дітей на землі своїй,
Назавжди від ворога звільненій!','["pisni.org.ua", "cat:povstanski", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5430141'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5430141','На моїй землі','На моїй землі - влада темряви,
Шабаш нечисти, час пітьми.
Ворог виміряв, що я вимріяв,
Й топче чорними чобітьми.

Не навік, однак, укарбовані
В степ і ліс чужинські сліди...
Лину в ґрунт дощем, змию знак біди
На моїй землі окупованій.

Рев чужих пісень замість солов''їв -
Де той звук, щоб з ним сперечавсь?
Щоби кулемет своє соло вів -
Вже не час, а мо'', ще не час.

У льохи й під стріхи захований,
Арсенал чекає часу,
Як пихатих зайд знайде правий суд
На моїй землі окупованій.

Мережі нема. Сам за себе дій.
Та чи вдієш щось, коли сам?
Браття з сестрами, наче лебеді,
Клином рушили в небеса.

Хто на Сході впав, замордований,
Хто на Захід вирвався й зник...
Лиш відлунням крук відповість на крик
На моїй землі окупованій.

Тануть в присмерку краю обриси,
Розчинюсь до ранку і я -
Щоб приміряти, в іншім образі,
Іншу тактику та ім''я.

Щоб вести в реальності зміненій
В інший спосіб - той самий бій:
За життя дітей на землі своїй,
Назавжди від ворога звільненій!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5429242','Мій найкращий друг','Музика: Morphom Слова: Morphom. Виконує: Morphom','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я досі не можу скласти твій пазл,
Сили нас залишають та не назавжди...
Ми йдемо назустріч, але так довго,
Ми йдемо назустріч, але так довго...
Час втікає від нас, поки ми вмираєм...
Все, що треба в нас є, але цього мало...
Мало... Може не всі, кому ти відкриваєш,
Буде тим, хто іде з тобою далі...

Приспів:
Мій найкращий друг!..          |
Але ти - мій найкращий друг!.. |
Мій найкращий друг!..          |
Але ти - мій найкращий друг!.. | (2)

Знаю, в тебе все добре, в мене - так само,
Болі немає там, де довго боліло,
З часом все одно як і що буде з нами...
Часові все одно як би ми не хотіли,
Час втікає від нас, поки ми чекаєм...
Той, хто був не за нас, їм усього мало,
Може, я з тих, хто забагато має?..
А, може, ми з тих, хто досі нікого не мали?..

Приспів.','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5429242'), datetime('now')),datetime('now'));
