INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5416040','Темна ніченька прийшла','Музика: народна Слова: Зоряна Лісевич','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Люлі-люлі, а-а-а,
Темна ніченька прийшла,
Принесла із далини
Кольорові гарні сни.
А-а-а-а-а-а-а-а-а-а...

Тихо блимають в імлі
З неба зіроньки малі.
Киця вклалася клубком
І дрімає під вікном.
А-а-а-а-а-а-а-а-а-а...

За порогом  світлячки
Світять срібні свічечки,
А на комині цвіркун
Скрипку взяв, торкнувся струн...
А-а-а-а-а-а-а-а-а-а...

Лиш не спить стара сова -
Снів казкових вартова.
Стереже солодкі сни,
Щоб наснилися вони...
А-а-а-а-а-а-а-а-а-а...

Люлі-люлі, а-а-а-а,
Гойда, гойда, гойда-да.
Колисаночка скрипить,
А дитятко міцно спить...
А-а-а-а-а-а-а-а-а-а...

Темна ніченька прийшла.
Люлі-люлі, а-а-а...','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5416040'), datetime('now')),datetime('now'));
