INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5439444','Мов поцілунок сонця','Музика: Богдан Весоловський Слова: Богдан Весоловський','uk','ukr_ssr_1919_1991',NULL,'1950','аудіозапис','Рідкісний запис Василя Тисяка на початку 1950-тих років, США.','Як я зустрів тебе одного дня,
Здавалось вже, що тільки ти одна
Без чар кохання
І щасливі дні зумієш дать мені!..

