Із нашої любові лиш
Спомин нам остав...','["pisni.org.ua", "cat:romansy", "Романси"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5439444'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5439444','Мов поцілунок сонця','Як я зустрів тебе одного дня,
