INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_541343','Ден бы-м косив','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Лемківські співанки. Зібрав і упорядкував М. Соболевський. — К.: Музична Україна, 1967. — 320 с.','Пісня з добірки М.Соболевського: Лемківські співанки Діалектизми: ани - ані; бы-м - би я; ден - день; жебы-м - якби я; женичка - жіночка, дружинонька; лем - тільки; мя - мене; наважи - наважся; роваж -?','Ден бы-м косив Ден бы-м косив Ден бы-м жав
Жебы-м тебе Дівчино собі взяв
Ани коси ани коси ани жни
Лем наважи лем наважи та й возми

Ой на роваж Мамичко на роваж
Ой кому ж ты Дівчатко виховаш
Ой тобі то Миленький тобі то
Будеш мати Женичку на літо

Ой Дівчино чия ты чия ты
Підеш зо мном гуляти-гуляти
Не питай ся чия я чия я
Як мя возмеш піду я піду я','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_541343'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_541343','Ден бы-м косив','Ден бы-м косив Ден бы-м косив Ден бы-м жав
Жебы-м тебе Дівчино собі взяв
Ани коси ани коси ани жни
Лем наважи лем наважи та й возми

Ой на роваж Мамичко на роваж
Ой кому ж ты Дівчатко виховаш
Ой тобі то Миленький тобі то
