INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5438848','Івана Купала','Музика: Pahatam Слова: Alina Pash. Виконує: Alina Pash','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Нині Сонцеворот,
