INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_544302','Автореквієм','(Було таке передчуття). Музика: Михайло Зарічний Слова: Олег Малашевський. Виконує: ПереBANDя, Михайло Зарічний','uk','ukraine_1991',NULL,NULL,'Надав М. Зарічний.','АНТИ-РЕКВІЄМ У Олега Малашевського є багато віршів, та найголовнішим серед них я вважаю "Автореквієм (було таке передчуття)". Кілька років тому я написав на ці слова пісню. Треба сказати, пісня не надавалася до виконання на вечірках чи в колі друзів, бо перемикала компанію на інший лад (терпіння, панове, незабаром самі зрозумієте, в чому суть). Щоби згладити депресивні враження, я придумав відеокліп на цю пісню. Як мені стало незабаром зрозуміло, матеріалізувати ідею відеокліпа не так просто, отож спробую описати сценарій на папері, апелюючи до уваги читача. Спочатку екран темний, звучить вступ на саксофоні: мі-мі-мііі-Мі-ре-до-сі-ля-сі і т. д. соль#-ля-сі-до-ляяяяя Потрохи сіріє і ми бачимо інтер''єр карпатської хати, де сплять троє чоловіків, один на лаві, один на бамбетлі, а ще один на печі. Той, що на лаві, підкручує брехунець на підвіконнику, музика звучить голосніше, потрохи прокидаються інші. Ось вже один вмивається, інший вибігає з виходка, застібаючи штани (а на дворі зима). Нарешті всі троє по зимовому одягнені надворі і тепер видно, що це весільні музиканти: скрипка, цимбали і бубон. Цимбаліст витягує з кишені і розгортає листок з портретом чоловіка середнього віку в траурній рамці, скрипаль — карту, вони дивляться, показують рукою вперед і рушають засніженими горами. Починається пісня. Я помер у люту зиму, з дзвоном впав на лід. На снігу сліпучім зринув мій прощальний слід. Видно, як музиканти віддаляються сніговою гірською дорогою, їх постаті все зменшуються. Вітер грав холодні вальси, (Тут в музику вклинюються тріолі; партія бубна: бум-цик-цик, бум-цик-цик.) срібний саван шив, а мороз затиснув пальці на моїй душі. Кадрами з старого, чорно-білого кіно показують фрагменти з життя цього чоловіка. Ось мама витирає десь так п''ятирічній дитині носа. Прийом в піонери. (А музиканти все йдуть, долаючи перевал.) Пиття вина "Ізабелла" біля сільського клубу підчас танців. Стало легко, тепло стало, обіравася біль, рвала коси, вичитала сива заметіль. Знов кадри: невміле тискання нареченої в весільному платті, вона при цьому позіхає. (Музиканти маленькими цяточками майже на обрії.) Я лежав красиво-синій, вперше мудрим став, як ніхто, колючий іній губи цілував. Наш герой став начальником: видно чергу відвідувачів до його кабінету. Він визирає з дверей, показує на годинник і вішає табличку: "Перерва", видно потім як всередині кабінету вони з іншими начальниками п''ють 50 гр. (Ось музиканти вже з''являються з-за перевалу.) Я звалив цю непотребу, міх життя з плечей, милувались тихо небом ковзанки очей. По устах поіневілих Чистий усміх плив. Мужики могилу рили і мене кляли." Камера перелітає через гори, обганяючи музикантів, видно мужиків, що довбають мерзлу землю. Вони перегукуються, неминуча при цьому ненормативна лексика заглушується свистом. Далі грається сама мелодія, яку наш невеликий оркестр виконує біля могили. При цьому, відповідно до подальших слів, показується, як жінка пробує кинутися вслід за домовиною в могилу, її відтягують. А ось двоє, відвернувшись від натовпу, пробують з пляшки якийсь міцний напій (холодно ж). Хтось сльозу пролив, хтось плюнув на душі полин. І схилилась Вічність юна до моїх колін. Розпорядники розраховуються з музикантами, ті ділять між собою гроші, ховають в кишеню. За якийсь час один з них витягує з кишені складене вчетверо фото ще якогось чоловіка в траурній рамці, інший витягує карту. Вони дивляться, показують рукою, куди йти, і рушають... Нарешті доходить черга і до Анти-Реквієма. Спасибі друзям за ідею щось таке написати. А щодо музики, то пригадується історія про "Because", одну з моїх улюблених бітлівських речей. Начебто Йоко Оно грала на роялі "Місячну сонату" Беетовена, а Джон Ленон попросив зіграти мелодію в протилежному напрямку, отак і вийшла тема "Because". Спробую застосувати цей трюк до "Автореквієма". Звичайно, антитеза не може бути ліпшою за тезу, та вже як є... — Михайло Зарічний, уривок з опусу "Вербалізація верболозу" Підбір акордів: М. Зарічний','Bm
Я помер у люту зиму
Em
