INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5442405','Три слова','Музика: Kozak System Слова: Сергій Соловій. Виконує: Kozak System','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Хто зна де, хто зна коли
Вона літала,
А він писав вірші.
Вірші про неї,
В яких всього лиш три,
Всього три слова писав
Від щастя і журби.
Серед сміття вродливих тіл,
Поміж безкрайніх сторіз,
У "каруселі" ці слова
Тонули, наче в морі...
Вмить забувала їх вона,
Кружляючи в нірвані,
А він писав, писав,
Щоб знов з''явитись на екрані...

Приспів:
І побачить вона ці три слова,
Усміхнеться і скаже: Я готова
За тобою піти хоч на небо!..
Хоч на край землі!..
Хоч на край землі!..
Хоч на край землі, якщо треба!..

Хто зна як, хто зна куди
Вона зникала,
А він шукав сліди.
Шукав в мережах,
По темних закутках,
Куди впускають лише
По золотих картках.
Та все ж писав він ті слова,
В яких всього три ноти,
Акорд мінорний так звучав,
Що плакали фаготи...
Але між ними вже ніколи
Не зітруться грані,
А він все пише і пише,
Щоб знов з''явитись на екрані...

Приспів.

Хто зна де, хто зна коли
Вона літала,
А він шукав сліди...','["pisni.org.ua", "cat:romansy", "Романси"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5442405'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5442405','Три слова','Хто зна де, хто зна коли
Вона літала,
А він писав вірші.
Вірші про неї,
В яких всього лиш три,
Всього три слова писав
Від щастя і журби.
Серед сміття вродливих тіл,
Поміж безкрайніх сторіз,
У "каруселі" ці слова
Тонули, наче в морі...
Вмить забувала їх вона,
Кружляючи в нірвані,
А він писав, писав,
Щоб знов з''явитись на екрані...

Приспів:
І побачить вона ці три слова,
Усміхнеться і скаже: Я готова
За тобою піти хоч на небо!..
Хоч на край землі!..
Хоч на край землі!..
Хоч на край землі, якщо треба!..

Хто зна як, хто зна куди
Вона зникала,
А він шукав сліди.
Шукав в мережах,
По темних закутках,
Куди впускають лише
По золотих картках.
Та все ж писав він ті слова,
В яких всього три ноти,
Акорд мінорний так звучав,
Що плакали фаготи...
Але між ними вже ніколи
Не зітруться грані,
А він все пише і пише,
Щоб знов з''явитись на екрані...

Приспів.

Хто зна де, хто зна коли
Вона літала,
А він шукав сліди...');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_5442405_l1','pisniua_5442405','YouTube','https://www.youtube.com/watch?v=AsbP5RIv4IY','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_54405','Чорнії брови, карії очі','(До карих очей). Слова: Костянтин Думитрашко. Виконує: Анатолій Солов''яненко, Іван Козловський','uk','ukraine_before_1917',NULL,NULL,NULL,'Відео: http://video.yandex.ru/users/mihalichasm/view/58/?cauthor=mihalichasm&cid=6','Чорнії брови, карії очі,
Темні як нічка, ясні як день,
Карії очі - чарі дівочі!
Де ви навчились зводить людей.

Чорнії брови, карії очі,
Страшно дивитись на вас під час.
Не будеш спати іноді ночі,
Все будеш думать, очі про вас.

Вас і немає, а ви мов тута.
Світите в душу, як дві зорі.
Чи в вас улита яка отрута,
Чи, може, й самі ви знахарі.

Чорнії брови - стрічки шовкові!
Все б тільки вами я любувавсь!
Карі очиці - очі тернові!
Все б я дивився тільки на вас.

Карії очі. Ви поробили,
Наворожили ви щось мені.
Та од пристріту, оченьки милі,
Тільки й поможете ви одні.    Фонограма-мінус (mp3)','["pisni.org.ua", "cat:lirychni", "cat:romansy", "Пісні про кохання, ліричні", "Романси"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_54405'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_54405','Чорнії брови, карії очі','Чорнії брови, карії очі,
Темні як нічка, ясні як день,
Карії очі - чарі дівочі!
Де ви навчились зводить людей.

Чорнії брови, карії очі,
Страшно дивитись на вас під час.
Не будеш спати іноді ночі,
Все будеш думать, очі про вас.

Вас і немає, а ви мов тута.
Світите в душу, як дві зорі.
Чи в вас улита яка отрута,
Чи, може, й самі ви знахарі.

Чорнії брови - стрічки шовкові!
Все б тільки вами я любувавсь!
Карі очиці - очі тернові!
Все б я дивився тільки на вас.

Карії очі. Ви поробили,
Наворожили ви щось мені.
Та од пристріту, оченьки милі,
Тільки й поможете ви одні.    Фонограма-мінус (mp3)');
