INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_5424106_l1','pisniua_5424106','YouTube','https://www.youtube.com/watch?v=nrGTuBfLN1M','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5449601','Ой, жни, дівча, пшениченьку',NULL,'uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, жни, дівча, пшениченьку
Та й не думай собі,
Буде тота пшениченька
На коровай тобі!

А як будеш, дівчинонько.
Думати, думати,
Буде твоя пшениченька
В полі зимувати.

Ти, дівчино чорнявая,
Ти, дівчино біла,
Чи ти в полі не робила,
Що ж не обгоріла?

А я в полі, легіники,
Жала і в''язала,
Але-м своє біле личко
Хустков закривала.

Якби-с була, дівчинонько,
Того не сказала,
Була би-с ся, моя любко,
Сих м''ясниць віддала.

Ой, я в полі та робила
І робити буду,
Але-м роду біленького
Та й біленька буду.','["pisni.org.ua", "cat:obzhynkovi", "Обжинкові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5449601'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5449601','Ой, жни, дівча, пшениченьку','Ой, жни, дівча, пшениченьку
