INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5449646','Що в моєї родини',NULL,'uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Що в моєї родини
Верне жито з ниви,
А у мене, нещасної,
Нема й колосини.

Що в моєї родини
Жито та пшениця,
А у мене, нещасної,
Горох та мітлиця.

Що в моєї родини
Женці дожинають,
А у мене, нещасної,
Журавлі збирають.','["pisni.org.ua", "cat:obzhynkovi", "Обжинкові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5449646'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5449646','Що в моєї родини','Що в моєї родини
