INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_54444_l1','pisniua_54444','YouTube','https://www.youtube.com/watch?v=RbgLgsWAZig','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5450545','Враже','Музика: Енджі Крейда Слова: Людмила Горова. Виконує: Енджі Крейда','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Сію тобі в очі,
Сію проти ночі.
Буде тобі, враже,
Так, як Відьма скаже!
Скільки в святу землю
Впало зерен жита -
Стільки разів буде
Тебе, враже вбито!
Скільки, враже, півень
Вночі кукуріка -
Стільки днів у тебе
Доживати віка!
Богові - Боже!
Ворогу - вороже!
Буде тобі, враже,
Так, як Відьма скаже!

Скільки зробиш, враже,
Кроків по Вкраїні -
Стільки твого ляже
Роду в домовині!
Стане на півсвіту
Чорного пристріту,
Буде тобі, враже,
Так, як Відьма скаже!
Писанку розпишу,
Люльку заколишу,
Матір твою, враже,
Без дітей залишу!
Батька твого, враже,
Смертю заспокою,
Жінку твою, враже,
Висушу ганьбою!
Богові - Боже!
Ворогу - вороже!
Буде тобі, враже,
Так, як Відьма скаже!

Як просію горе
Крізь дрібненьке сито -
Станеш ти про пекло
Господа просити...
Та не буде, враже,
Смерть твоя легкою.
Та й у смерті, враже,
Не знайдеш спокою...
Слово моє липке,
Слово моє кріпке,
Буде тобі, враже,
Так, як мати скаже!
Буде тобі, враже,
Як дружина скаже!
Буде тобі, враже,
Як дівчина скаже!
Буде тобі, враже,
Як дитина скаже!
Буде тобі, враже,
Так, як Відьма скаже!','["pisni.org.ua", "cat:viyskovi", "Пісні на військову тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5450545'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5450545','Враже','Сію тобі в очі,
