INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5431900','Поки ніхто не бачить','Музика: Макс Пташник Слова: Макс Пташник','uk','ukraine_1991',NULL,NULL,'https://www.youtube.com/watch?v=GGH5f1HHANo','Пісню виконує Макс Пташник (альбом - Буденна пересічна драма).','На даний момент відсутній зв''язок
З вашим абонентом,
Зателефонуйте, будь ласка, пізніше...

Впусти в своє серце
Невідоме, незнайоме,
Біль та втому облиш,
Віддайся новому,
Виходь із дому!..
У спогадах ти кричиш,
Лікуй свої рани новими днями.
Образи старі залиш...
Занурюєш в тишу і не залишу
Догадки із ким ти спиш...

Приспів:
Поки ніхто не бачить,
Я досі тебе люблю!..
Поки ніхто не бачить,
Я досі тебе люблю!..
І поки ніхто не бачить,
Я досі тебе люблю!..
Поки ніхто не бачить...
Поки ніхто не бачить...

Поки ніхто не бачить,
Я сам на сам воюю із собою...
Серце у вічному конфлікту з головою,
Хоч це не має сенсу - я вже не з тобою,
Поки ніхто не бачить,
Бракує сил коханню дати здачі...
Чому життя на тебе далі трачу?..
Колись я виросту і все пробачу!..

Приспів.','["pisni.org.ua", "cat:nostalgia", "Пісні з ностальгічними мотивами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5431900'), datetime('now')),datetime('now'));
