INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5453545','Ванька встанька','Музика: Маша Кондратенко Слова: Маша Кондратенко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ви казали, що не знали,
Ой як вийшло, як же так?
У дібровах ви блукали,
Куди бігти, як же так?
Ой, ми бачим ваші сльозки,
Страшно вам, аж гай шумить!
Скаже навіть баба з возу,
Що вас всіх треба спалить!

Приспів:
Ванька, встань-ка, що таке? |
Приготуй собі пакет!        |
Ванька-встанька, не біжи!   |
Вже немає куди йти!         | (2)

Ванька встанька!..
Ванька встанька!..

Не сховатися нікому,
То хіба що по приколу.
Морем-полем йде козак,
То для вас недобрий знак!
Раз! Два! Три! Чотири! П''ять!
Вам нема куди тікать!
Раз! Два! Три! Чотири! П''ять!
Наш козак іде шукать!

Приспів.','["pisni.org.ua", "cat:ato", "cat:viyskovi", "cat:zhartivlyvi", "Пісні російсько-української війни та АТО", "Пісні на військову тематику", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5453545'), datetime('now')),datetime('now'));
