INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5454704','Чути гімн','Музика: Володимир Самолюк Слова: Володимир Самолюк. Виконує: Володимир Самолюк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
В небі чистому чути грім,    |
В небі свист, але чути гімн! |
В небі чистому мутний дим... |
Горить ліс, але чути гімн!   | (2)

За нами правда, значить
Вистоїм ми ваші вистріли!
За нами правда, а її
Ніяк не пристрелить!
За нами правда, значить
Визволим село ми за селом!
За нами правда, значить
Ми з долин повиганям зло!
Ну, а поки будем бить вас
За Азов і Бучу!
За Дніпрові кручі!
За Ірпінь, який ти мучив!
За лани квітучі!
За Херсон - землю родючу!
За Донбас получиш!
За Чернігів неминуче!
За ліси дрімучі!
За Хмельницького Богдана!
За Франка Івана!
І за Суми, і за храми
ЗСУ прийде за вами!
І за ночі, і за рани,
За кожен тривожний ранок!
За Харків і тюльпани!
За Одесу маму!
За Рівне і Здолбунів,
За Полтаву, Львів і пулі!
За Київ, Луцьк, за Вінницю,
За Миколаїв - дулі!
За Чернівці, Черкаси,
Тернопіль і Кривий Ріг,
За Запоріжжя, і Житомир,
І за Крим забуться, - гріх!

Приспів','["pisni.org.ua", "cat:ato", "cat:patriotic", "cat:viyskovi", "Пісні російсько-української війни та АТО", "Патріотичні пісні", "Пісні на військову тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5454704'), datetime('now')),datetime('now'));
