INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5453807','Така красива','Музика: Ельбрус Джанмірзоєв Слова: Олексій Мороз','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
Така красива! Ти така красива!     |
Зроблю я все, щоб ти була щаслива! |
Така красива, рідна і жадана!      |
Я бережу тебе, моя кохана!         | (2)

Я задивлюся у твої очі,
Без них так сумно мені щоночі...
З тоблю разом хоч на край світу!..
Ти - моя осінь!.. Ти - моє літо!..
Тобі дарую кохання крила -
Лети зі мною ти, моя мила!
Міцно цілую і обіймаю,
Коли далеко - тоді чекаю!

Приспів.

Поїдем разом на тепле море!
Поїдем разом високо в гори!
Я завжди поруч! Я біля тебе!
Ти - мої хмари і моє небо!
А твої губи такі солодкі,
З тобою ночі завжди короткі!
Коли далеко - завжди сумую...
І з-поміж інших тебе почую!..

Приспів.','["pisni.org.ua", "cat:ato", "cat:devoted", "Пісні російсько-української війни та АТО", "Пісні присвячені окремим особам"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5453807'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5453807','Така красива','Приспів:
Така красива! Ти така красива!     |
Зроблю я все, щоб ти була щаслива! |
Така красива, рідна і жадана!      |
Я бережу тебе, моя кохана!         | (2)

Я задивлюся у твої очі,
Без них так сумно мені щоночі...
З тоблю разом хоч на край світу!..
Ти - моя осінь!.. Ти - моє літо!..
Тобі дарую кохання крила -
Лети зі мною ти, моя мила!
Міцно цілую і обіймаю,
Коли далеко - тоді чекаю!

Приспів.

Поїдем разом на тепле море!
Поїдем разом високо в гори!
Я завжди поруч! Я біля тебе!
Ти - мої хмари і моє небо!
А твої губи такі солодкі,
З тобою ночі завжди короткі!
Коли далеко - завжди сумую...
І з-поміж інших тебе почую!..

Приспів.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_5453807_l1','pisniua_5453807','YouTube','https://www.youtube.com/watch?v=jCYjVSLUhkg','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5457141','Настане час','Музика: Andrii Soloviov Alexandr Leonov, Alexandr Bortnikov Слова: Lida Lee, Мішель СайкаліLida Lee, Мішель Сайкалі','uk','ukraine_1991',NULL,NULL,'аудіозапис','Автори музики: Andrii Soloviov Alexandr Leonov, Alexandr Bortnikov, Nazar Vachevskiy, Oleh Kalaid, Vova Pavlovsky, Marii Sorokina, Roman Dudnik.','Настане час!..
Ми всі побачимося знов!
І в нашій країні
Лиш співатиме любов!
Слава Україні!
Все пройдемо разом ми!
Ці слова в серцях
З нами назавжди!..
Настане час!
І переможемо ми -
Кожна дитина спокійно
Бачитиме сни!..
Вільне, синє небо,
Світанок мирний за вікном,
Всі разом ми
Спокійно мріятимемо знов!

Приспів:
Один ми світ, ми — Україна!
Чекає вдома жінка чоловіка,
Мати - сина!
Хай зігріє нас любов,
Надія і віра,
Бо жити мирно й вільно -
Це українська мрія!

Настане час!..
І кожен з нас забуде страх!
Але не забудем, як палали
Наші міста в вогнях!..
Рідна Україно,
З тобою назавжди!
Ми цілим світом відсвяткуєм
Перемогу наших сил!

Приспів

Разом з тобою ми пройдемо
Крізь всі шляхи,
Ти лиш тримай мою руку в своїй руці!
Темрява не переможе світло,
Що в кожного з нас!
Я обійму тебе, як знов
Настане мирний час!

Приспів. (3)

Бо жити мирно й вільно -
Це твоя і моя мрія!
Настане час!..','["pisni.org.ua", "cat:ato", "cat:viyskovi", "Пісні російсько-української війни та АТО", "Пісні на військову тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5457141'), datetime('now')),datetime('now'));
