INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_545508','Гомін, гомін, гомін по діброві','Українська народна пісня. Виконує: Хор "Чумаки"','uk','ukr_ssr_1919_1991',NULL,'1989','1. Українські народні пісні. Кн. 1. — К.: "Мистецтво", 1955. — с. 46. 2. Триліс В.','З 1989 року - в постійному репертуарі чоловічого народного хору "Чумаки" під орудою В. Триліса (м. Київ). Існують досить відмінні варіанти тексту (очевидно, зумовлені змінами історичних обставин) та різні мелодії - наприклад, у постанові "Наталка-полтавка".','Гомін, гомін, гомін по діброві,
Туман поле покриває,
Туман поле, поле покриває,
Мати сина проганяє.

- Іди, сину, іди пріч від мене,
Хай тебе татарин візьме!
- Мене, мамо, татарин боїться,
В чистім полі сторониться.

- Іди, сину, іди пріч від мене,
Нехай тебе орда візьме!
- Мене, мамо, мене й орда знає,
В чистім полі обминає.

- Іди, сину, іди пріч від мене,
Нехай тебе москаль візьме!
- Мене, мамо, мене й москаль знає,
К собі в гості підмовляє.

- Вернись, вернись, вернись, мій синоньку,
Змию тобі головоньку!
- Мені, мамо, мені змиють дощі,
А розчешуть буйні вітри.

Гомін, гомін, гомін по діброві,
Туман поле покриває.
Миють дощі, миють білі кості, -
Син додому не вертає','["pisni.org.ua", "cat:dumy", "cat:istorychni", "cat:kozacki", "cat:philosophic", "cat:socialno-pobutovi", "cat:suspilno-politychni", "Думи", "Історичні пісні", "Козацькі пісні", "Філософські пісні", "Соціально-побутові пісні", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_545508'), datetime('now')),datetime('now'));
