INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5455343','Котився віночок по полю','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Котився віночок по полю,
Да просився женчиків додому:

Ой, додому, женчики, ходіте,
Да мене у стодолу візьміте!

Нехай же я в стодолі спочину,
А восени знову на поле вилину.

Бо вже я дрібного дощику напився,
Вже ж я буйних вітриків начувся!

Вже ж я од соненька напікся,
Од ясного місяця насвітився,
На яснії зіроньки надивився!','["pisni.org.ua", "cat:obzhynkovi", "Обжинкові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5455343'), datetime('now')),datetime('now'));
