INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5456848','Хвилями','Музика: Аліса Панчук, Валерія Кудрявець Слова: Аліса Панчук, Валерія Кудрявець. Виконує: SKYLERR','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
Хвилями у морі несе течія,
В незнаній просторі
Забува своє ім''я..
Важко уявити, що тебе нема,
Я так хочу жити, тебе обійма!
Хвилями, хви-хви-хвилями!    |
Хвилями, хви-хви-хвилями!    |
Хвилями, хвилями несе течія! | (2)

На руці тату - символ надії,
Символ любові, української мрії,
Пообіцяй, що мене не залишиш!
Пообіцяй, що я стану сильніша!
Сильна і вільна, така незалежна!
Вона, як море, як поле, безмежна!
І я до тебе у вир з головою
На хвилях ночі, на хвилях любові!

Приспів.

Тебе-тебе обійма!
Очі палають, коли не сама...
Тебе-тебе обійма!
Тривоги нема, нема!..

Хвилями, хви-хви-хвилями!    |
Хвилями, хви-хви-хвилями!    |
Хвилями, хвилями несе течія! | (2)

Речитатив:
Кохайтесь, чорнобриві,
Та не з москалями,
Бо москалі - чужі люде,
Роблять лихо з вами...','["pisni.org.ua", "cat:ato", "cat:devoted", "cat:viyskovi", "Пісні російсько-української війни та АТО", "Пісні присвячені окремим особам", "Пісні на військову тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5456848'), datetime('now')),datetime('now'));
