INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5458003','Журавлі','Музика: Олена Білоконь Слова: Зоя Журавка','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Там журавлі летіли клином
Вечірнім небом за селом.
А батько сивий, мати сива,
Дивились в небо за вікном...
Один журавлик повернувся,
Змахнувши їм своїм крилом,
І наче сином обернувся,
Почувся голос під вікном.

Приспів:
Мамо, мамо! -
Він крикнув криком журавлиним,
Мамо, мамо!
І янголом злетів у вись!...
Чуєш, тату,
Я захищав свою країну,
А ви живіть!
А ви живіть тут, як колись!

Я вас прошу, мене пробачте,
Інакше просто не зумів!..
Болить, я знаю, та не плачте!
І в небо янголом злетів!
Голосить матінка за сином,
А батько, наче скам''янів,
Вдивляється у небо синє,
Когось з-за хмар чекає він...
А ключ у небі журавлиний
Махає їм з небес крильми,
То не сім''я літа пташина -
То наші янголи сини!

Приспів.

А ви живіть!
А ви живіть тут, як колись!','["pisni.org.ua", "cat:ato", "cat:nostalgia", "cat:pro-ditey", "cat:viyskovi", "Пісні російсько-української війни та АТО", "Пісні з ностальгічними мотивами", "Пісні про любов до дітей", "Пісні на військову тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5458003'), datetime('now')),datetime('now'));
