І помилуй нас!         | (2)    Мелодія із словами','["pisni.org.ua", "cat:cerkovni", "cat:christ", "cat:strasni", "Церковні пісні", "Пісні до Ісуса Христа", "Страсні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_546106'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_546106','Чоловіче добрий','Чоловіче добрий,
