INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5458646','Біля серця','Музика: KOLA Слова: Іван Клименко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'А, що, якби тебе зі мною не звело?..
А, що, якби наші дороги замело?..
А, що, якби не взяв мене ти під крило?..
Коли моя душа замерзла - подарував тепло!..
А, що, якби на фронті загубив шолом
І після цього повідомлення від тебе
Не прийшло, але я чую... Мій телефон,
Він каже, що ти на зв''язку
І ми будем разом!

Приспів:
Я тебе ношу в кишені біля серця,
Бо лише з тобою воно б''ється!..
Поки ти в кишені біля серця,
Я жива!.. Я! Я жива!
Я тебе ношу в кишені біля серця,
Бо лише з тобою воно б''ється!..
Поки ти в кишені біля серця,
Я жива!.. Я! Я жива!
You''re іn my heart!
You''re іn my heart!
You''re іn my heart!

А, що, якби забула я до рідних номери?..
А, що, якби не було з ким навіть поговорить?..
А, що, якби ми раптом всі стали старі,
І зрозуміли, що не цінували кожну мить?..
Якби я знов мала і за родинним столом,
То побажала би всім частіше бачитись знов!
Куди б мене, тебе і всіх нас не занесло,
Цінуймо те, що є, а не те, що не було!..

Приспів.','["pisni.org.ua", "cat:ato", "cat:devoted", "cat:lirychni", "cat:philosophic", "cat:viyskovi", "Пісні російсько-української війни та АТО", "Пісні присвячені окремим особам", "Пісні про кохання, ліричні", "Філософські пісні", "Пісні на військову тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5458646'), datetime('now')),datetime('now'));
