INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_5458646_l1','pisniua_5458646','YouTube','https://www.youtube.com/watch?v=7u4g9ByyBX8','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5464900','Народна','Музика: Люся Кава Слова: Люся Кава. Виконує: Люся Кава','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ми всі - одна родина!
Ми всі - одна країна!
Від батька і до сина,
Славимо її!
Біда нас не зламала!
Вона нас об''єднала!
Віра нас захищала
На всі роки!

Приспів:
Ми - вільний народ!
Сильний народ!
Могутній народ!
Слава Україні!  |
Героям слава!   |
Слава Україні!  |
Героям слава!   |
Слава Україні!  |
Героям слава!   |
Смерть ворогам! | (2)

Ми всі - велика сила,
І кожна тут людина!
То є моя країна!
Бережіть її!

Приспів.','["pisni.org.ua", "cat:patriotic", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5464900'), datetime('now')),datetime('now'));
