INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5462848','Працює ППО','Музика: Роман Гороховських Слова: Роман Гороховських','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Кажуть, плани - непотрібна річ.
Як там буде - знає тільки Бог.
Може й так, але приходить ніч,
Ніч - це час повітряних тривог.
З нами Бог,
Та, щоб спокійно спати
Недостатньо Бога одного:
Їм всю ніч потрібно працювати
Місто спить.
Працює ППО! Працює ППО! | (4)

Кат прийшов до нашої землі,
Свій металобрухт до нас припер,
Буде лізти, поки у кремлі
Нечистю керує людожер.
Та не може він спокійно спати,
Він не розуміє одного:
Всі його ракети - марні втрати,
Бо у нас
Працює ППО! Працює ППО! | (4)

Годі вже ховатись під землею!
Знищить кляту нечисть Україна!
Брухт металу вкриється іржею,
На катів чекає домовина!
Боже Україну захищає
ЗСУ - представники його!
То не янгол в небі пролітає,
То відпрацювала ППО!
Працює ППО! Працює ППО! | (3)

Працює Україна! Та працює ППО!','["pisni.org.ua", "cat:ato", "Пісні російсько-української війни та АТО"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5462848'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5462848','Працює ППО','Кажуть, плани - непотрібна річ.
