INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5466405','Ангел ЗСУ','Музика: Ганна Глинська Слова: Ганна Глинська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ховати сльози в коси
Я так і не навчилась,
Життя дає момент,
З яким ти не змирилась...
Моє серденько туга,
Неспокій накриває,
Бо ти не поряд, милий,
Війна тебе плекає...

Приспів:
Мій Янгол ЗСУ,
Я чекаю! Я люблю!
Я помолюсь тихо Богу,
Хай зміцнить твій дух в бою!
Мій Янгол ЗСУ,
Я цілунок тобі шлю,
Нехай він загоїть рани,
Наче тепло моїх рук!..
Мій Янгол ЗСУ!..
Мій Янгол!.. Мій Янгол!..

У обіймах твоїх
Хочу загорнутись!..
В твої теплі очі
Впасти і забутись!..
І коли у тобі
Втону я до дна,
Залишаєш і йдеш,
Де смерті нема кінця...
Боже, збережи!

Приспів.','["pisni.org.ua", "cat:ato", "Пісні російсько-української війни та АТО"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5466405'), datetime('now')),datetime('now'));
