INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_547003','Коло млина ясенина','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Б. Д. Гринченко. Этнографические материалы, собранные в Черниговской и соседних с ней губерниях, т. III. Чернигов, 1899, с. 385 (м. Нова Ушиця на Поділлі).',NULL,'Коло млина ясенина,
Зацвіла калина.
Захотіла в саду спати
Молода дівчина.

Захотіла вона спати
Межи яблоньками,
Щоби була розмовонька
Всю ніч з парубками.

"Дай же мені, моя мати,
Вишиту сорочку.
Грають хлопці в дудочку
В вишневім садочку.

Дай же мені, моя мати,
Да й червоний пояс,
Бо (уже) я десь зачула
Парубоцький голос.

Дай же мені, моя мати,
Да й червону бинду,
Не замикай сінних дверей,
Бо я зараз прийду".

Молодая невісточка
Та й сидить на лавці:
"Ой не пускай, мати, дочки,
Вона любить хлопці".

"Бодай же ти, невісточко,
Та й відти не встала;
Більше люди говорили,
Та й мати не знала".','["pisni.org.ua", "cat:podilski", "Пісні з Поділля"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_547003'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_547003','Коло млина ясенина','Коло млина ясенина,
Зацвіла калина.
