INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_547040','Беру воду та з переброду','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'М. Лисенко. Збірник українських народних пісень, вип. І - VII. К., (1868 - 1911), V, с. 65.',NULL,'Беру воду та з переброду,
