INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5467601','У темноті над містом','Музика: Володимир Грабар Слова: Володимир Грабар','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'У темноті над містом,
Над містом, над містом
Горить зоря провісна,
Провісна, провісна.

Приспів:
Не в пишнім царськім домі, |
А в яслах на соломі        |
Родився наш спаситель -    |
Ісус Христос!              | (2)

А зверху спів небесний,
Небесний, небесний
Лунає день чудесний,
Чудесний, чудесний!

Приспів.

А пастухи приходять,
Приходять, приходять,
Дитя в яслах знаходять,
Знаходять, знаходять.

Приспів.

Давайте всі підемо,
Підемо, підемо,
Рожденного знайдемо,
Знайдемо, знайдемо!

Приспів.

У темноті над містом,
Над містом, над містом...','["pisni.org.ua", "cat:kolyadky", "cat:shchedrivky", "cat:suchasni-pisni-rizdvo", "Колядки", "Щедрівки", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5467601'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5467601','У темноті над містом','У темноті над містом,
