INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_5467601_l2','pisniua_5467601','YouTube','https://www.youtube.com/watch?v=bkuU-Jlu9Fc','video',NULL,2);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5471807','Правда','Музика: Андрій Хливнюк Слова: Сергій Жадан, Андрій Хливнюк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ходить повітрям утомлений Яків,
Значить межу між зимою і літом.
Човен рибальський кидає якір,
Ніби пакетик із чаєм Ліптон.
Рання пора безнадійно впертих,
Пора повертань і пора продовжень...
Ось капітан розглядає берег,
Наче газету старих оголошень...
Скільки вивчати води зимові?..
Як прочитати знаки повчальні?..
Мудрість - вона не лише у слові,
Але й в мовчанні!.. В мовчанні!..
Скільки питань у ранковій мові,
Гаснуть поволі вогні причальні...
Щедрість - вона не лише у любові,
Але й в прощанні!..

Приспів:
Той капітан - щирість!..
Той капітан - радість!..
Той капітан - вірність!..
Той капітан - правда!..
Правда!.. Правда!..

Рване повітрям, наче вітрила,
Вітер ламає нічні причали...
Мені важливо, що ти говорила,
І надважливо, про що мовчала!..
Жовто до ранку світять ліхтарні,
Світять знесилено, до знемоги...
В небі зимовому, ніби в лікарні,
Живуть відвертості й тривоги...
Дивна пора відчайдушно сміливих,
Довгі часи голосних і тихих,
Гоїться по осінніх зливах
Моря нічного болючий вивих...
Скільки питань у ранковій мові,
Гаснуть поволі вогні причальні...
Мудрість - вона не лише у слові,
Але й в мовчанні!..

Приспів.

Той капітан, що у шторм, в неспокій,
Вголос сміється і люльку палить,
Той, хто думки твої знав напам''ять,
Любив тебе і твоє дно глибоке,
Йому байдужі чужі причали,
Тиша, мов повінь, проти повчання,
Мудрість його не лише у слові,
Але й в мовчанні!.. В мовчанні!..

Приспів.

Правда!.. Правда!.. Правда!..','["pisni.org.ua", "cat:devoted", "cat:philosophic", "cat:viyskovi", "Пісні присвячені окремим особам", "Філософські пісні", "Пісні на військову тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5471807'), datetime('now')),datetime('now'));
