INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_547343','Ясмін','(Весняне). Музика: Ольга Богомолець Слова: Олена Теліга. Виконує: Ольга Богомолець','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Приспів:
Розцвітають кущі ясміну,
Грає сонце в височині,
Чи зустріну, чи не зустріну?
Чи побачу тебе, чи ні?

І куди б скерувати кроки,
Щоб тебе я могла знайти?
Тільки бачу, - іде високий,
Придивляюсь, чи то ж не ти...

Приспів.

І не вітряно, і не хмарно,
Все заповнив весняний сміх.
Цілий день проброжу я марно,
Не зустрівши очей твоїх.

Приспів.

Та зате серед ночі, любий,
В весняному моєму сні, -
Поцілуєш мої ти губи
І щось тихо шепнеш мені.

Приспів.','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_547343'), datetime('now')),datetime('now'));
