INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5475444','Ой у лузі червона калина','Українська народна пісня. Виконує: Рок-гурт Natalika','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'відеофайл','Червона калина - Рок-версія гурту Natalika. Аранжування, рок-гітара та вокал - Наталія Горщар. Продакшн студія "Natalika". Саундклауд 👉 https://soundcloud.com/user-859064446...','Ой у лузі червона калина похилилася,
Чогось наша славна Україна зажурилася.
А ми тую червону калину підіймемо,
А ми нашу славну Україну,
Гей, гей, розвеселимо!

Не хилися, червона калино,
Маєш білий цвіт!
Не журися, славна Україно,
Маєш вільний рід!
А ми тую червону калину підіймемо,
А ми нашу славну Україну,
Гей, гей, розвеселимо!

Як повіє буйнесенький вітер
З широких степів,
Та й прославить по всій Україні
Січових стрільців.
А ми тую стрілецькую славу збережемо,
А ми нашу славну Україну,
Гей, гей, розвеселимо!','["pisni.org.ua", "cat:kozacki", "cat:povstanski", "cat:strilecki", "Козацькі пісні", "Повстанські пісні", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5475444'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5475444','Ой у лузі червона калина','Ой у лузі червона калина похилилася,
Чогось наша славна Україна зажурилася.
А ми тую червону калину підіймемо,
А ми нашу славну Україну,
Гей, гей, розвеселимо!

Не хилися, червона калино,
Маєш білий цвіт!
Не журися, славна Україно,
Маєш вільний рід!
А ми тую червону калину підіймемо,
А ми нашу славну Україну,
Гей, гей, розвеселимо!

Як повіє буйнесенький вітер
З широких степів,
Та й прославить по всій Україні
Січових стрільців.
А ми тую стрілецькую славу збережемо,
А ми нашу славну Україну,
Гей, гей, розвеселимо!');
