INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_547900','Інструкція','Музика: Тризубий Стас Слова: Тризубий Стас. Виконує: Тризубий Стас','uk','ukraine_1991',NULL,NULL,NULL,'Підбір акордів: Кук','Жителі Житомиру Полтави та Черкас
Партія з заявою звертається до вас
Вам мабуть відомо що готується візит
Західних бандерівців на червоний схід

Ту орду спрямовує до наших міст і сіл
Головний ОУНівець Бандера-Чорновіл
Виплекав на Львівщині націоналізм
І вся ота зараза пре на червоний комунізм

Приспів:
Попереджає інструкція, що може бути ексцес
Захистимо революцію і рідну нашу КПCC

Якби ви десь побачили небажаних гостей
Двері закривайте, ховайте десь дітей,
Не ходіть по вулиці бо заріжут чи забют
Бандери як відомо кров дитячу пють

А ще вони охочі до житомирських дівок
Хоч мають там на заході по три по п''ять жінок
Можуть постраждати молоді чоловіки
Вони там через одного усі ґвалтівники

Приспів.

Всі вони страховиська руки до землі
Пазурі на пальцях роги на чолі
Мають по три ока і собачий хвіст
Отакий на вигляд є націоналіст

У кожного нагострений золотий тризуб
Штрикне вас по череву вважайте шо ви труп
А як захоче їсти то в нього без проблем
Лапає комуніста і ковта його живцем','["pisni.org.ua", "cat:suspilno-politychni", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_547900'), datetime('now')),datetime('now'));
