INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5494949','Справжня дружба','Музика: Ольга Маєвська Слова: Микола Тихонов','uk','ukraine_1991',NULL,NULL,'авторське подання','Пісню виконує Ольга Маєвська (альбом: Пісні для дітей).','Людина може жити й не тужити,
Коли умітиме по-справжньому дружити!
Бо друг в житті - це вам не просто так,
А це, напевно, що від Бога знак!

Товариша не можна ображати,
Його потрібно вміти поважати!
Не кидайте ви друга у біді -
Він допоможе й вам колись тоді!

Умійте й порадіти ви за друга,
І ви забудете відтак, що таке туга!
Робіть добро й великі і малі,
І будуть друзями всі люди на землі!','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5494949'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5494949','Справжня дружба','Людина може жити й не тужити,
Коли умітиме по-справжньому дружити!
Бо друг в житті - це вам не просто так,
А це, напевно, що від Бога знак!

Товариша не можна ображати,
Його потрібно вміти поважати!
Не кидайте ви друга у біді -
Він допоможе й вам колись тоді!

Умійте й порадіти ви за друга,
І ви забудете відтак, що таке туга!
Робіть добро й великі і малі,
І будуть друзями всі люди на землі!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_5494949_l1','pisniua_5494949','YouTube','https://www.youtube.com/watch?v=zxuQLUsQTCE','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5494646','Пес','Музика: Ольга Маєвська Слова: Надія Семена','uk','ukraine_1991',NULL,NULL,'авторське подання','Пісню виконує Ольга Маєвська (альбом: Пісні для дітей).','В кожному в домі потрібен свій пес,
Знай, для господаря він — антистрес,
Він охоронець і просто дружбан,
З ним можна сісти удвох на диван.

По телевізору глянуть кіно.
Поговорити, про що — все одно,
Уважно послухає, не переб''є,
Вроджений такт у собак точно є!

Псу мало треба: лиш корм для собак,
Зранку гуляти сходити у парк,
Трішки уваги, любов, доброта,
Дружня підтримка — то справа свята!','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5494646'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5494646','Пес','В кожному в домі потрібен свій пес,
