INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_550003','Пишу листа','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,NULL,'Студенти 70х співали цю пісню в гуртожитках, не знаючи що це за пісня. Дізналися, коли підселили в корпус кілька нквдистів. А пісня, коли хто ще не здогадався, виявилася бандерівською. Так от від тих "студентів":)','Студенти 70х співали цю пісню в гуртожитках, не знаючи що це за пісня. Дізналися, коли підселили в корпус кілька нквдистів. А пісня, коли хто ще не здогадався, виявилася бандерівською. Так от від тих "студентів":)','Я вмираю і пишу листа, може лист цей вже і не дійде,
Може ти не знаєш, де я є, може хтось мене ще і знайде...

Приспів:
Ти не плач, матусю, я прошу, памятай, що я любив тебе,
Твою знімку цілий час ношу, вибач мамо за усе мене.

Вірю я, що переможем ми, не проллється більш даремно кров,
На руїнах рабства буде дим, верх візьме тоді людська любов

Приспів:
Ти не плач, матусю, я прошу, памятай, що я любив тебе,
Твою знімку цілий час ношу, вибач мамо за усе мене.','["pisni.org.ua", "cat:halycki", "cat:povstanski", "Пісні з Галичини", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_550003'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_550003','Пишу листа','Я вмираю і пишу листа, може лист цей вже і не дійде,
