INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5505405','Вишивала шила мати сорочину','Слова: Василь Чопей','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Вишивала, шила
Мати сорочину
Та й сказала мила:
Це тобі, мій сину!
Це тобі, синочку,
В подарунок, милий,
Вишию сорочку,
Та носи щасливий!
Щоб не знав за горе,
Щоб не знав за лихо,
Вишию в узори
Прошептала тихо...

Наче та машина
Не втомлялась шити
І навчала сина,
Як правильно жити.
Будь веселим добрим,
А в лиху годину
Сильним та хоробрим
Люби Батьківщину!
Люби Україну
Чарівну казкову,
Її солов''їну
Свою Рідну мову!

Зможеш то й чужого
Залюбки навчайся
Та ніколи свого,
Синку, не цурайся!
Від душі всієї
Люби землю свою
І завжди за неї
Будь готов до бою!
Люби гори й доли -
Наставляла мати,
І не дай ніколи
Ворогам топтати!','["pisni.org.ua", "cat:pro-ditey", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5505405'), datetime('now')),datetime('now'));
