INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5504807','Зозуля','Музика: Володимир Засухін Слова: Юрій Рибчинський','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Один стою серед дерев, що мов поснули,
Ці голоси мої думки перевернули...
Немов коваль, кує мені зозуля роки,
Багато літ, та завжди хочеться ще трохи...

Приспів:
Скільки би зозуля років не кувала,     |
Все одно, зозуля, мені буде мало!..    |
Скільки б ти, зозуля, років не кувала, |
Мало, мало буде, знай!..               | (2)

Давним-давно я народивсь, і слава Богу!..
Пив, як вино, я кожну мить життя хмільного...
Пив, як вино кохання кожну мить шалену,
Та все одно жага життя сильніш за мене!..

Приспів.

Один стою серед дерев, що мов поснули,
І у гаю я чую, знов кує зозуля...
Немов коваль, кує мені зозуля роки,
Багато літ, та завжди хочеться ще трохи...

Приспів.','["pisni.org.ua", "cat:philosophic", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5504807'), datetime('now')),datetime('now'));
